103	function normalizeStringListRecord(value: unknown): Record<string, string[]> | undefined {
104	  if (!isRecord(value)) {
105	    return undefined;
106	  }
107	  const normalized: Record<string, string[]> = {};
108	  for (const [key, rawValues] of Object.entries(value)) {
109	    const providerId = typeof key === "string" ? key.trim() : "";
110	    if (!providerId) {
111	      continue;
112	    }
113	    const values = normalizeStringList(rawValues);
114	    if (values.length === 0) {
