107	export type CandidateBlockReason =
108	  | "source_escapes_root"
109	  | "path_stat_failed"
110	  | "path_world_writable"
111	  | "path_suspicious_ownership";
112	
113	type CandidateBlockIssue = {
114	  reason: CandidateBlockReason;
115	  sourcePath: string;
116	  rootPath: string;
117	  targetPath: string;
118	  sourceRealPath?: string;
119	  rootRealPath?: string;
120	  modeBits?: number;
121	  foundUid?: number;
122	  expectedUid?: number;
123	};
124	
125	function checkSourceEscapesRoot(params: {
126	  source: string;
127	  rootDir: string;
128	}): CandidateBlockIssue | null {
129	  const sourceRealPath = safeRealpathSync(params.source);
130	  const rootRealPath = safeRealpathSync(params.rootDir);
131	  if (!sourceRealPath || !rootRealPath) {
132	    return null;
133	  }
134	  if (isPathInside(rootRealPath, sourceRealPath)) {
135	    return null;
136	  }
137	  return {
138	    reason: "source_escapes_root",
139	    sourcePath: params.source,
140	    rootPath: params.rootDir,
141	    targetPath: params.source,
142	    sourceRealPath,
143	    rootRealPath,
144	  };
145	}
146	
147	function checkPathStatAndPermissions(params: {
148	  source: string;
149	  rootDir: string;
150	  origin: PluginOrigin;
151	  uid: number | null;
152	}): CandidateBlockIssue | null {
153	  if (process.platform === "win32") {
154	    return null;
155	  }
156	  const pathsToCheck = [params.rootDir, params.source];
157	  const seen = new Set<string>();
158	  for (const targetPath of pathsToCheck) {
159	    const normalized = path.resolve(targetPath);
160	    if (seen.has(normalized)) {
161	      continue;
162	    }
163	    seen.add(normalized);
164	    let stat = safeStatSync(targetPath);
165	    if (!stat) {
166	      return {
167	        reason: "path_stat_failed",
168	        sourcePath: params.source,
169	        rootPath: params.rootDir,
170	        targetPath,
171	      };
172	    }
173	    let modeBits = stat.mode & 0o777;
174	    if ((modeBits & 0o002) !== 0 && params.origin === "bundled") {
175	      // npm/global installs can create package-managed extension dirs without
176	      // directory entries in the tarball, which may widen them to 0777.
177	      // Tighten bundled dirs in place before applying the normal safety gate.
178	      try {
179	        fs.chmodSync(targetPath, modeBits & ~0o022);
180	        const repairedStat = safeStatSync(targetPath);
181	        if (!repairedStat) {
182	          return {
183	            reason: "path_stat_failed",
184	            sourcePath: params.source,
185	            rootPath: params.rootDir,
186	            targetPath,
187	          };
188	        }
189	        stat = repairedStat;
190	        modeBits = repairedStat.mode & 0o777;
191	      } catch {
192	        // Fall through to the normal block path below when repair is not possible.
193	      }
194	    }
195	    if ((modeBits & 0o002) !== 0) {
196	      return {
197	        reason: "path_world_writable",
198	        sourcePath: params.source,
199	        rootPath: params.rootDir,
200	        targetPath,
201	        modeBits,
202	      };
203	    }
204	    if (
205	      params.origin !== "bundled" &&
206	      params.uid !== null &&
207	      typeof stat.uid === "number" &&
208	      stat.uid !== params.uid &&
209	      stat.uid !== 0
210	    ) {
211	      return {
212	        reason: "path_suspicious_ownership",
213	        sourcePath: params.source,
214	        rootPath: params.rootDir,
215	        targetPath,
216	        foundUid: stat.uid,
217	        expectedUid: params.uid,
218	      };
219	    }
220	  }
221	  return null;
222	}
223	
224	function findCandidateBlockIssue(params: {
225	  source: string;
226	  rootDir: string;
227	  origin: PluginOrigin;
228	  ownershipUid?: number | null;
229	}): CandidateBlockIssue | null {
230	  const escaped = checkSourceEscapesRoot({
231	    source: params.source,
232	    rootDir: params.rootDir,
233	  });
234	  if (escaped) {
235	    return escaped;
236	  }
237	  return checkPathStatAndPermissions({
238	    source: params.source,
239	    rootDir: params.rootDir,
240	    origin: params.origin,
241	    uid: currentUid(params.ownershipUid),
242	  });
243	}
244	
245	function formatCandidateBlockMessage(issue: CandidateBlockIssue): string {
246	  if (issue.reason === "source_escapes_root") {
247	    return `blocked plugin candidate: source escapes plugin root (${issue.sourcePath} -> ${issue.sourceRealPath}; root=${issue.rootRealPath})`;
248	  }
249	  if (issue.reason === "path_stat_failed") {
250	    return `blocked plugin candidate: cannot stat path (${issue.targetPath})`;
251	  }
252	  if (issue.reason === "path_world_writable") {
253	    return `blocked plugin candidate: world-writable path (${issue.targetPath}, mode=${formatPosixMode(issue.modeBits ?? 0)})`;
254	  }
255	  return `blocked plugin candidate: suspicious ownership (${issue.targetPath}, uid=${issue.foundUid}, expected uid=${issue.expectedUid} or root)`;
256	}
257	
258	function isUnsafePluginCandidate(params: {
259	  source: string;
260	  rootDir: string;
261	  origin: PluginOrigin;
262	  diagnostics: PluginDiagnostic[];
263	  ownershipUid?: number | null;
264	}): boolean {
265	  const issue = findCandidateBlockIssue({
266	    source: params.source,
267	    rootDir: params.rootDir,
268	    origin: params.origin,
269	    ownershipUid: params.ownershipUid,
270	  });
271	  if (!issue) {
272	    return false;
273	  }
274	  params.diagnostics.push({
275	    level: "warn",
276	    source: issue.targetPath,
277	    message: formatCandidateBlockMessage(issue),
278	  });
279	  return true;
280	}
