157	function createPluginJitiLoader(options: Pick<PluginLoadOptions, "pluginSdkResolution">) {
158	  const jitiLoaders = new Map<string, ReturnType<typeof createJiti>>();
159	  return (modulePath: string) => {
160	    const tryNative = shouldPreferNativeJiti(modulePath);
161	    const aliasMap = buildPluginLoaderAliasMap(
162	      modulePath,
163	      process.argv[1],
164	      import.meta.url,
165	      options.pluginSdkResolution,
166	    );
167	    const cacheKey = JSON.stringify({
168	      tryNative,
169	      aliasMap: Object.entries(aliasMap).toSorted(([left], [right]) => left.localeCompare(right)),
170	    });
171	    const cached = jitiLoaders.get(cacheKey);
172	    if (cached) {
173	      return cached;
174	    }
175	    const loader = createJiti(import.meta.url, {
176	      ...buildPluginLoaderJitiOptions(aliasMap),
177	      // Source .ts runtime shims import sibling ".js" specifiers that only exist
178	      // after build. Disable native loading for source entries so Jiti rewrites
179	      // those imports against the source graph, while keeping native dist/*.js
180	      // loading for the canonical built module graph.
181	      tryNative,
182	    });
183	    jitiLoaders.set(cacheKey, loader);
184	    return loader;
185	  };
186	}
