227	  registryCache.set(cacheKey, state);
228	  while (registryCache.size > pluginRegistryCacheEntryCap) {
229	    const oldestKey = registryCache.keys().next().value;
230	    if (!oldestKey) {
231	      break;
232	    }
233	    registryCache.delete(oldestKey);
234	  }
235	}
