95	function resolveManifestCacheMs(env: NodeJS.ProcessEnv): number {
96	  const raw = env.OPENCLAW_PLUGIN_MANIFEST_CACHE_MS?.trim();
97	  if (raw === "" || raw === "0") {
98	    return 0;
99	  }
100	  if (!raw) {
101	    return DEFAULT_MANIFEST_CACHE_MS;
102	  }
103	  const parsed = Number.parseInt(raw, 10);
104	  if (!Number.isFinite(parsed)) {
105	    return DEFAULT_MANIFEST_CACHE_MS;
106	  }
107	  return Math.max(0, parsed);
108	}
