133	  // It does not depend on allow/deny/entries enable-state, so exclude those for higher cache hit rates.
134	  return `${workspaceKey}::${configExtensionsRoot}::${bundledRoot}::${runtimeServiceVersion}::${JSON.stringify(loadPaths)}`;
