201	      meta: {
202	        id: CHANNEL_ID,
203	        label: "Synology Chat",
204	        selectionLabel: "Synology Chat (Webhook)",
205	        detailLabel: "Synology Chat (Webhook)",
206	        docsPath: "/channels/synology-chat",
207	        blurb: "Connect your Synology NAS Chat to OpenClaw",
208	        order: 90,
209	      },
210	      capabilities: {
211	        chatTypes: ["direct" as const],
212	        media: true,
213	        threads: false,
214	        reactions: false,
215	        edit: false,
216	        unsend: false,
217	        reply: false,
218	        effects: false,
219	        blockStreaming: false,
220	      },
221	      reload: { configPrefixes: [`channels.${CHANNEL_ID}`] },
222	      configSchema: SynologyChatChannelConfigSchema,
223	      setup: synologyChatSetupAdapter,
224	      setupWizard: synologyChatSetupWizard,
225	      config: {
226	        ...synologyChatConfigAdapter,
227	      },
228	      auth: synologyChatApprovalAuth,
229	      messaging: {
230	        normalizeTarget: (target: string) => {
231	          const trimmed = target.trim();
232	          if (!trimmed) return undefined;
233	          // Strip common prefixes
234	          return trimmed.replace(/^synology[-_]?chat:/i, "").trim();
235	        },
236	        targetResolver: {
237	          looksLikeId: (id: string) => {
238	            const trimmed = id?.trim();
239	            if (!trimmed) return false;
240	            // Synology Chat user IDs are numeric
241	            return /^\d+$/.test(trimmed) || /^synology[-_]?chat:/i.test(trimmed);
242	          },
243	          hint: "<userId>",
244	        },
245	      },
246	      directory: createEmptyChannelDirectoryAdapter(),
247	      gateway: {
248	        startAccount: async (ctx: SynologyChannelGatewayContext) => {
249	          const { cfg, accountId, log, abortSignal } = ctx;
250	          const account = resolveAccount(cfg, accountId);
251	          if (!validateSynologyGatewayAccountStartup({ cfg, account, accountId, log }).ok) {
252	            return waitUntilAbort(abortSignal);
