93	/**
94	 * Resolve a specific account by ID with full defaults applied.
95	 * Falls back to env vars for the "default" account.
96	 */
97	export function resolveAccount(
98	  cfg: OpenClawConfig,
99	  accountId?: string | null,
100	): ResolvedSynologyChatAccount {
101	  const channelCfg = getChannelConfig(cfg) ?? {};
102	  const id = accountId || DEFAULT_ACCOUNT_ID;
103	  const accountOverrides =
104	    id === DEFAULT_ACCOUNT_ID ? undefined : (channelCfg.accounts?.[id] ?? undefined);
105	  const rawAccount = getRawAccountConfig(channelCfg, id);
106	  const merged = resolveMergedAccountConfig<Record<string, unknown> & SynologyChatChannelConfig>({
107	    channelConfig: channelCfg as Record<string, unknown> & SynologyChatChannelConfig,
108	    accounts: channelCfg.accounts as
109	      | Record<string, Partial<Record<string, unknown> & SynologyChatChannelConfig>>
110	      | undefined,
111	    accountId: id,
112	  });
113	
114	  // Env var fallbacks (primarily for the "default" account)
115	  const envToken = process.env.SYNOLOGY_CHAT_TOKEN ?? "";
116	  const envIncomingUrl = process.env.SYNOLOGY_CHAT_INCOMING_URL ?? "";
117	  const envNasHost = process.env.SYNOLOGY_NAS_HOST ?? "localhost";
118	  const envAllowedUserIds = process.env.SYNOLOGY_ALLOWED_USER_IDS ?? "";
119	  const envRateLimitValue = parseRateLimitPerMinute(process.env.SYNOLOGY_RATE_LIMIT);
120	  const envBotName = process.env.OPENCLAW_BOT_NAME ?? "OpenClaw";
121	  const webhookPathSource = resolveWebhookPathSource({ accountId: id, channelCfg, rawAccount });
122	  const dangerouslyAllowInheritedWebhookPath =
123	    rawAccount.dangerouslyAllowInheritedWebhookPath ??
124	    channelCfg.dangerouslyAllowInheritedWebhookPath ??
125	    false;
126	
127	  // Merge: account override > base channel config > env var
128	  return {
129	    accountId: id,
130	    enabled: merged.enabled ?? true,
131	    token: merged.token ?? envToken,
132	    incomingUrl: merged.incomingUrl ?? envIncomingUrl,
133	    nasHost: merged.nasHost ?? envNasHost,
134	    webhookPath: merged.webhookPath ?? "/webhook/synology",
135	    webhookPathSource,
136	    dangerouslyAllowNameMatching: resolveDangerousNameMatchingEnabled({
137	      providerConfig: channelCfg,
138	      accountConfig: accountOverrides,
139	    }),
140	    dangerouslyAllowInheritedWebhookPath,
141	    dmPolicy: merged.dmPolicy ?? "allowlist",
142	    allowedUserIds: parseAllowedUserIds(merged.allowedUserIds ?? envAllowedUserIds),
143	    rateLimitPerMinute: merged.rateLimitPerMinute ?? envRateLimitValue,
144	    botName: merged.botName ?? envBotName,
145	    allowInsecureSsl: merged.allowInsecureSsl ?? false,
146	  };
147	}
