29	type InvalidTokenRateLimitState = {
30	  count: number;
31	  windowStartMs: number;
32	};
33	
34	class InvalidTokenRateLimiter {
35	  private readonly limit: number;
36	  private readonly state = new Map<string, InvalidTokenRateLimitState>();
37	
38	  constructor(limit: number) {
39	    this.limit = limit;
40	  }
41	
42	  private normalizeState(key: string, nowMs: number): InvalidTokenRateLimitState | undefined {
43	    const existing = this.state.get(key);
44	    if (!existing) {
45	      return undefined;
46	    }
47	    if (nowMs - existing.windowStartMs >= INVALID_TOKEN_WINDOW_MS) {
48	      this.state.delete(key);
49	      return undefined;
50	    }
51	    return existing;
52	  }
53	
54	  private touch(key: string, value: InvalidTokenRateLimitState): void {
55	    this.state.delete(key);
56	    this.state.set(key, value);
57	    while (this.state.size > INVALID_TOKEN_MAX_TRACKED_KEYS) {
58	      const oldestKey = this.state.keys().next().value;
59	      if (!oldestKey) {
60	        break;
61	      }
62	      this.state.delete(oldestKey);
63	    }
64	  }
65	
66	  isLocked(key: string, nowMs = Date.now()): boolean {
67	    if (!key) {
68	      return false;
69	    }
70	    const existing = this.normalizeState(key, nowMs);
71	    return (existing?.count ?? 0) > this.limit;
72	  }
73	
74	  recordFailure(key: string, nowMs = Date.now()): boolean {
75	    if (!key) {
76	      return false;
77	    }
78	    const existing = this.normalizeState(key, nowMs);
79	    const nextCount = (existing?.count ?? 0) + 1;
80	    const windowStartMs = existing?.windowStartMs ?? nowMs;
81	    this.touch(key, { count: nextCount, windowStartMs });
82	    return nextCount > this.limit;
83	  }
84	
85	  clear(): void {
86	    this.state.clear();
87	  }
88	
89	  maxRequests(): number {
90	    return this.limit;
91	  }
92	}
