380	function authorizeSynologyWebhook(params: {
381	  req: IncomingMessage;
382	  account: ResolvedSynologyChatAccount;
383	  payload: SynologyWebhookPayload;
384	  invalidTokenRateLimiter: InvalidTokenRateLimiter;
385	  rateLimiter: RateLimiter;
386	  log?: WebhookHandlerDeps["log"];
387	}): SynologyWebhookAuthorization {
388	  const invalidTokenRateLimitKey = getSynologyWebhookInvalidTokenRateLimitKey(params.req);
389	  // Once a source has exhausted its invalid-token budget, reject all requests in the window.
390	  if (params.invalidTokenRateLimiter.isLocked(invalidTokenRateLimitKey)) {
391	    params.log?.warn(`Rate limit exceeded for remote IP: ${invalidTokenRateLimitKey}`);
392	    return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
393	  }
