1	/**
2	 * Synology Chat Channel Plugin for OpenClaw.
3	 *
4	 * Implements the ChannelPlugin interface following the LINE pattern.
5	 */
6	
7	import type { OpenClawConfig } from "openclaw/plugin-sdk/account-resolution";
8	import {
9	  createHybridChannelConfigAdapter,
10	  createScopedDmSecurityResolver,
11	} from "openclaw/plugin-sdk/channel-config-helpers";
12	import { waitUntilAbort } from "openclaw/plugin-sdk/channel-lifecycle";
13	import {
14	  composeWarningCollectors,
15	  createConditionalWarningCollector,
16	  projectAccountConfigWarningCollector,
17	  projectAccountWarningCollector,
18	} from "openclaw/plugin-sdk/channel-policy";
19	import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
20	import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";
21	import { createEmptyChannelDirectoryAdapter } from "openclaw/plugin-sdk/directory-runtime";
22	import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/setup";
23	import { listAccountIds, resolveAccount } from "./accounts.js";
24	import { synologyChatApprovalAuth } from "./approval-auth.js";
25	import { sendMessage, sendFileUrl } from "./client.js";
26	import { SynologyChatChannelConfigSchema } from "./config-schema.js";
27	import {
28	  collectSynologyGatewayRoutingWarnings,
29	  registerSynologyWebhookRoute,
30	  validateSynologyGatewayAccountStartup,
31	} from "./gateway-runtime.js";
32	import { synologyChatSetupAdapter, synologyChatSetupWizard } from "./setup-surface.js";
33	import type { ResolvedSynologyChatAccount } from "./types.js";
34	
35	const CHANNEL_ID = "synology-chat";
36	
37	const resolveSynologyChatDmPolicy = createScopedDmSecurityResolver<ResolvedSynologyChatAccount>({
38	  channelKey: CHANNEL_ID,
39	  resolvePolicy: (account) => account.dmPolicy,
40	  resolveAllowFrom: (account) => account.allowedUserIds,
41	  policyPathSuffix: "dmPolicy",
42	  defaultPolicy: "allowlist",
43	  approveHint: "openclaw pairing approve synology-chat <code>",
44	  normalizeEntry: (raw) => raw.toLowerCase().trim(),
45	});
46	
47	type SynologyChannelGatewayContext = {
48	  cfg: OpenClawConfig;
49	  accountId: string;
50	  abortSignal: AbortSignal;
51	  log?: {
52	    info: (message: string) => void;
53	    warn: (message: string) => void;
54	    error: (message: string) => void;
55	  };
56	};
57	type SynologyChannelOutboundContext = {
58	  cfg: OpenClawConfig;
59	  to: string;
60	  text?: string;
61	  mediaUrl?: string;
62	  accountId?: string | null;
63	};
64	type SynologyChannelSendTextContext = SynologyChannelOutboundContext & { text: string };
65	type SynologyChannelSendMediaContext = SynologyChannelOutboundContext & { mediaUrl: string };
66	type SynologySecurityWarningContext = {
67	  cfg: OpenClawConfig;
68	  account: ResolvedSynologyChatAccount;
69	};
70	
71	const synologyChatConfigAdapter = createHybridChannelConfigAdapter<ResolvedSynologyChatAccount>({
72	  sectionKey: CHANNEL_ID,
73	  listAccountIds,
74	  resolveAccount,
75	  defaultAccountId: () => DEFAULT_ACCOUNT_ID,
76	  clearBaseFields: [
77	    "token",
78	    "incomingUrl",
79	    "nasHost",
80	    "webhookPath",
81	    "dangerouslyAllowNameMatching",
82	    "dangerouslyAllowInheritedWebhookPath",
83	    "dmPolicy",
84	    "allowedUserIds",
85	    "rateLimitPerMinute",
86	    "botName",
87	    "allowInsecureSsl",
88	  ],
89	  resolveAllowFrom: (account) => account.allowedUserIds,
90	  formatAllowFrom: (allowFrom) =>
91	    allowFrom.map((entry) => String(entry).trim().toLowerCase()).filter(Boolean),
92	});
93	
94	const collectSynologyChatSecurityWarnings =
95	  createConditionalWarningCollector<ResolvedSynologyChatAccount>(
96	    (account) =>
97	      !account.token &&
98	      "- Synology Chat: token is not configured. The webhook will reject all requests.",
99	    (account) =>
100	      !account.incomingUrl &&
101	      "- Synology Chat: incomingUrl is not configured. The bot cannot send replies.",
102	    (account) =>
103	      account.allowInsecureSsl &&
104	      "- Synology Chat: SSL verification is disabled (allowInsecureSsl=true). Only use this for local NAS with self-signed certificates.",
105	    (account) =>
106	      account.dangerouslyAllowNameMatching &&
107	      "- Synology Chat: dangerouslyAllowNameMatching=true re-enables mutable username/nickname recipient matching for replies. Prefer stable numeric user IDs.",
108	    (account) =>
109	      account.dangerouslyAllowInheritedWebhookPath &&
110	      account.webhookPathSource === "inherited-base" &&
111	      "- Synology Chat: dangerouslyAllowInheritedWebhookPath=true opts a named account into a shared inherited webhook path. Prefer an explicit per-account webhookPath.",
112	    (account) =>
113	      account.dmPolicy === "open" &&
114	      '- Synology Chat: dmPolicy="open" allows any user to message the bot. Consider "allowlist" for production use.',
115	    (account) =>
116	      account.dmPolicy === "allowlist" &&
117	      account.allowedUserIds.length === 0 &&
118	      '- Synology Chat: dmPolicy="allowlist" with empty allowedUserIds blocks all senders. Add users or set dmPolicy="open".',
119	  );
120	
121	type SynologyChatOutboundResult = {
122	  channel: typeof CHANNEL_ID;
123	  messageId: string;
124	  chatId: string;
125	};
126	
127	type SynologyChatPlugin = Omit<
128	  ChannelPlugin<ResolvedSynologyChatAccount>,
129	  "pairing" | "security" | "messaging" | "directory" | "outbound" | "gateway" | "agentPrompt"
130	> & {
131	  pairing: {
132	    idLabel: string;
133	    normalizeAllowEntry?: (entry: string) => string;
134	    notifyApproval: (params: { cfg: OpenClawConfig; id: string }) => Promise<void>;
135	  };
136	  security: {
137	    resolveDmPolicy: (params: { cfg: OpenClawConfig; account: ResolvedSynologyChatAccount }) => {
138	      policy: string | null | undefined;
139	      allowFrom?: Array<string | number>;
140	      normalizeEntry?: (raw: string) => string;
141	    } | null;
142	    collectWarnings: (params: {
143	      cfg: OpenClawConfig;
144	      account: ResolvedSynologyChatAccount;
145	    }) => string[];
146	  };
147	  messaging: {
148	    normalizeTarget: (target: string) => string | undefined;
149	    targetResolver: {
150	      looksLikeId: (id: string) => boolean;
151	      hint: string;
152	    };
153	  };
154	  directory: {
155	    self?: NonNullable<ChannelPlugin<ResolvedSynologyChatAccount>["directory"]>["self"];
156	    listPeers?: NonNullable<ChannelPlugin<ResolvedSynologyChatAccount>["directory"]>["listPeers"];
157	    listGroups?: NonNullable<ChannelPlugin<ResolvedSynologyChatAccount>["directory"]>["listGroups"];
158	  };
159	  outbound: {
160	    deliveryMode: "gateway";
161	    textChunkLimit: number;
162	    sendText: (ctx: SynologyChannelSendTextContext) => Promise<SynologyChatOutboundResult>;
163	    sendMedia: (ctx: SynologyChannelOutboundContext) => Promise<SynologyChatOutboundResult>;
164	  };
165	  gateway: {
166	    startAccount: (ctx: SynologyChannelGatewayContext) => Promise<unknown>;
167	    stopAccount: (ctx: SynologyChannelGatewayContext) => Promise<void>;
168	  };
169	  agentPrompt: {
170	    messageToolHints: () => string[];
171	  };
172	};
173	
174	const collectSynologyChatRoutingWarnings = projectAccountConfigWarningCollector<
175	  ResolvedSynologyChatAccount,
176	  OpenClawConfig,
177	  SynologySecurityWarningContext
178	>(
179	  (cfg) => cfg,
180	  ({ account, cfg }) => collectSynologyGatewayRoutingWarnings({ account, cfg }),
181	);
182	
183	function resolveOutboundAccount(
184	  cfg: OpenClawConfig,
185	  accountId?: string | null,
186	): ResolvedSynologyChatAccount {
187	  return resolveAccount(cfg ?? {}, accountId);
188	}
189	
190	function requireIncomingUrl(account: ResolvedSynologyChatAccount): string {
191	  if (!account.incomingUrl) {
192	    throw new Error("Synology Chat incoming URL not configured");
193	  }
194	  return account.incomingUrl;
195	}
