197	export function createSynologyChatPlugin(): SynologyChatPlugin {
198	  return createChatChannelPlugin({
199	    base: {
200	      id: CHANNEL_ID,
201	      meta: {
202	        id: CHANNEL_ID,
203	        label: "Synology Chat",
204	        selectionLabel: "Synology Chat (Webhook)",
205	        detailLabel: "Synology Chat (Webhook)",
206	        docsPath: "/channels/synology-chat",
207	        blurb: "Connect your Synology NAS Chat to OpenClaw",
208	        order: 90,
209	      },
210	      capabilities: {
211	        chatTypes: ["direct" as const],
212	        media: true,
213	        threads: false,
214	        reactions: false,
215	        edit: false,
216	        unsend: false,
217	        reply: false,
218	        effects: false,
219	        blockStreaming: false,
220	      },
221	      reload: { configPrefixes: [`channels.${CHANNEL_ID}`] },
222	      configSchema: SynologyChatChannelConfigSchema,
223	      setup: synologyChatSetupAdapter,
224	      setupWizard: synologyChatSetupWizard,
225	      config: {
226	        ...synologyChatConfigAdapter,
227	      },
228	      auth: synologyChatApprovalAuth,
229	      messaging: {
230	        normalizeTarget: (target: string) => {
231	          const trimmed = target.trim();
232	          if (!trimmed) return undefined;
233	          // Strip common prefixes
234	          return trimmed.replace(/^synology[-_]?chat:/i, "").trim();
235	        },
236	        targetResolver: {
237	          looksLikeId: (id: string) => {
238	            const trimmed = id?.trim();
239	            if (!trimmed) return false;
240	            // Synology Chat user IDs are numeric
241	            return /^\d+$/.test(trimmed) || /^synology[-_]?chat:/i.test(trimmed);
242	          },
243	          hint: "<userId>",
244	        },
245	      },
246	      directory: createEmptyChannelDirectoryAdapter(),
247	      gateway: {
248	        startAccount: async (ctx: SynologyChannelGatewayContext) => {
249	          const { cfg, accountId, log, abortSignal } = ctx;
250	          const account = resolveAccount(cfg, accountId);
251	          if (!validateSynologyGatewayAccountStartup({ cfg, account, accountId, log }).ok) {
252	            return waitUntilAbort(abortSignal);
253	          }
254	
255	          log?.info?.(
256	            `Starting Synology Chat channel (account: ${accountId}, path: ${account.webhookPath})`,
257	          );
258	          const unregister = registerSynologyWebhookRoute({ account, accountId, log });
259	
260	          log?.info?.(`Registered HTTP route: ${account.webhookPath} for Synology Chat`);
261	
262	          // Keep alive until abort signal fires.
263	          // The gateway expects a Promise that stays pending while the channel is running.
264	          // Resolving immediately triggers a restart loop.
265	          return waitUntilAbort(abortSignal, () => {
266	            log?.info?.(`Stopping Synology Chat channel (account: ${accountId})`);
267	            unregister();
268	          });
269	        },
270	
271	        stopAccount: async (ctx: SynologyChannelGatewayContext) => {
272	          ctx.log?.info?.(`Synology Chat account ${ctx.accountId} stopped`);
273	        },
274	      },
275	      agentPrompt: {
276	        messageToolHints: () => [
277	          "",
278	          "### Synology Chat Formatting",
279	          "Synology Chat supports limited formatting. Use these patterns:",
280	          "",
281	          "**Links**: Use `<URL|display text>` to create clickable links.",
282	          "  Example: `<https://example.com|Click here>` renders as a clickable link.",
283	          "",
284	          "**File sharing**: Include a publicly accessible URL to share files or images.",
285	          "  The NAS will download and attach the file (max 32 MB).",
286	          "",
287	          "**Limitations**:",
288	          "- No markdown, bold, italic, or code blocks",
289	          "- No buttons, cards, or interactive elements",
290	          "- No message editing after send",
291	          "- Keep messages under 2000 characters for best readability",
292	          "",
293	          "**Best practices**:",
294	          "- Use short, clear responses (Synology Chat has a minimal UI)",
295	          "- Use line breaks to separate sections",
296	          "- Use numbered or bulleted lists for clarity",
297	          "- Wrap URLs with `<URL|label>` for user-friendly links",
298	        ],
299	      },
300	    },
301	    pairing: {
302	      text: {
303	        idLabel: "synologyChatUserId",
304	        message: "OpenClaw: your access has been approved.",
305	        normalizeAllowEntry: (entry: string) => entry.toLowerCase().trim(),
306	        notify: async ({ cfg, id, message }) => {
307	          const account = resolveAccount(cfg);
308	          if (!account.incomingUrl) return;
309	          await sendMessage(account.incomingUrl, message, id, account.allowInsecureSsl);
310	        },
311	      },
312	    },
313	    security: {
314	      resolveDmPolicy: resolveSynologyChatDmPolicy,
315	      collectWarnings: composeWarningCollectors(
316	        projectAccountWarningCollector<ResolvedSynologyChatAccount, SynologySecurityWarningContext>(
317	          collectSynologyChatSecurityWarnings,
318	        ),
319	        collectSynologyChatRoutingWarnings,
320	      ),
321	    },
322	    outbound: {
323	      deliveryMode: "gateway" as const,
324	      textChunkLimit: 2000,
325	
326	      sendText: async ({ to, text, accountId, cfg }: SynologyChannelSendTextContext) => {
327	        const account = resolveOutboundAccount(cfg ?? {}, accountId);
328	        const incomingUrl = requireIncomingUrl(account);
329	        const ok = await sendMessage(incomingUrl, text, to, account.allowInsecureSsl);
330	        if (!ok) {
331	          throw new Error("Failed to send message to Synology Chat");
332	        }
333	        return attachChannelToResult(CHANNEL_ID, { messageId: `sc-${Date.now()}`, chatId: to });
334	      },
335	
336	      sendMedia: async ({ to, mediaUrl, accountId, cfg }: SynologyChannelOutboundContext) => {
337	        const account = resolveOutboundAccount(cfg ?? {}, accountId);
338	        const incomingUrl = requireIncomingUrl(account);
339	        if (!mediaUrl) {
340	          throw new Error("No media URL provided");
341	        }
342	
343	        const ok = await sendFileUrl(incomingUrl, mediaUrl, to, account.allowInsecureSsl);
344	        if (!ok) {
345	          throw new Error("Failed to send media to Synology Chat");
346	        }
347	        return attachChannelToResult(CHANNEL_ID, { messageId: `sc-${Date.now()}`, chatId: to });
348	      },
349	    },
350	  }) as unknown as SynologyChatPlugin;
351	}
352	
353	export const synologyChatPlugin = createSynologyChatPlugin();
