49	function patchSynologyChatAccountConfig(params: {
50	  cfg: OpenClawConfig;
51	  accountId: string;
52	  patch: Record<string, unknown>;
53	  clearFields?: string[];
54	  enabled?: boolean;
55	}): OpenClawConfig {
56	  const channelConfig = getChannelConfig(params.cfg);
57	  if (params.accountId === DEFAULT_ACCOUNT_ID) {
58	    const nextChannelConfig = { ...channelConfig } as Record<string, unknown>;
59	    for (const field of params.clearFields ?? []) {
60	      delete nextChannelConfig[field];
61	    }
62	    return {
63	      ...params.cfg,
64	      channels: {
65	        ...params.cfg.channels,
66	        [channel]: {
67	          ...nextChannelConfig,
68	          ...(params.enabled ? { enabled: true } : {}),
69	          ...params.patch,
70	        },
71	      },
72	    };
73	  }
74	
75	  const nextAccounts = { ...(channelConfig.accounts ?? {}) } as Record<
76	    string,
77	    Record<string, unknown>
78	  >;
79	  const nextAccountConfig = { ...(nextAccounts[params.accountId] ?? {}) };
80	  for (const field of params.clearFields ?? []) {
81	    delete nextAccountConfig[field];
82	  }
83	  nextAccounts[params.accountId] = {
84	    ...nextAccountConfig,
85	    ...(params.enabled ? { enabled: true } : {}),
86	    ...params.patch,
87	  };
88	
89	  return {
90	    ...params.cfg,
91	    channels: {
92	      ...params.cfg.channels,
93	      [channel]: {
94	        ...channelConfig,
95	        ...(params.enabled ? { enabled: true } : {}),
96	        accounts: nextAccounts,
97	      },
98	    },
