31	/**
32	 * Check if a user ID is in the allowed list.
33	 * Allowlist mode must be explicit; empty lists should not match any user.
34	 */
35	export function checkUserAllowed(userId: string, allowedUserIds: string[]): boolean {
36	  if (allowedUserIds.length === 0) return false;
37	  return allowedUserIds.includes(userId);
38	}
