40	/**
41	 * Resolve DM authorization for a sender across all DM policy modes.
42	 * Keeps policy semantics in one place so webhook/startup behavior stays consistent.
43	 */
44	export function authorizeUserForDm(
45	  userId: string,
46	  dmPolicy: "open" | "allowlist" | "disabled",
47	  allowedUserIds: string[],
48	): DmAuthorizationResult {
49	  if (dmPolicy === "disabled") {
50	    return { allowed: false, reason: "disabled" };
51	  }
52	  if (dmPolicy === "open") {
53	    return { allowed: true };
54	  }
55	  if (allowedUserIds.length === 0) {
56	    return { allowed: false, reason: "allowlist-empty" };
57	  }
58	  if (!checkUserAllowed(userId, allowedUserIds)) {
59	    return { allowed: false, reason: "not-allowlisted" };
60	  }
61	  return { allowed: true };
62	}
