39	export { resolveDefaultNextcloudTalkAccountId };
40	
41	export function listNextcloudTalkAccountIds(cfg: CoreConfig): string[] {
42	  const ids = listNextcloudTalkAccountIdsInternal(cfg);
43	  debugAccounts("listNextcloudTalkAccountIds", ids);
44	  return ids;
45	}
46	
47	function mergeNextcloudTalkAccountConfig(
48	  cfg: CoreConfig,
49	  accountId: string,
50	): NextcloudTalkAccountConfig {
51	  return resolveMergedAccountConfig<NextcloudTalkAccountConfig>({
52	    channelConfig: cfg.channels?.["nextcloud-talk"] as NextcloudTalkAccountConfig | undefined,
53	    accounts: cfg.channels?.["nextcloud-talk"]?.accounts as
54	      | Record<string, Partial<NextcloudTalkAccountConfig>>
55	      | undefined,
56	    accountId,
57	    omitKeys: ["defaultAccount"],
58	    normalizeAccountId,
59	  });
60	}
61	
62	function resolveNextcloudTalkSecret(
63	  cfg: CoreConfig,
64	  opts: { accountId?: string },
65	): { secret: string; source: ResolvedNextcloudTalkAccount["secretSource"] } {
66	  const merged = mergeNextcloudTalkAccountConfig(cfg, opts.accountId ?? DEFAULT_ACCOUNT_ID);
67	
68	  const envSecret = process.env.NEXTCLOUD_TALK_BOT_SECRET?.trim();
69	  if (envSecret && (!opts.accountId || opts.accountId === DEFAULT_ACCOUNT_ID)) {
70	    return { secret: envSecret, source: "env" };
71	  }
72	
73	  if (merged.botSecretFile) {
74	    const fileSecret = tryReadSecretFileSync(
75	      merged.botSecretFile,
76	      "Nextcloud Talk bot secret file",
77	      { rejectSymlink: true },
78	    );
79	    if (fileSecret) {
80	      return { secret: fileSecret, source: "secretFile" };
81	    }
82	  }
83	
84	  const inlineSecret = normalizeResolvedSecretInputString({
85	    value: merged.botSecret,
86	    path: `channels.nextcloud-talk.accounts.${opts.accountId ?? DEFAULT_ACCOUNT_ID}.botSecret`,
87	  });
88	  if (inlineSecret) {
89	    return { secret: inlineSecret, source: "config" };
90	  }
91	
92	  return { secret: "", source: "none" };
93	}
94	
95	export function resolveNextcloudTalkAccount(params: {
96	  cfg: CoreConfig;
97	  accountId?: string | null;
98	}): ResolvedNextcloudTalkAccount {
99	  const baseEnabled = params.cfg.channels?.["nextcloud-talk"]?.enabled !== false;
100	
101	  const resolve = (accountId: string) => {
102	    const merged = mergeNextcloudTalkAccountConfig(params.cfg, accountId);
103	    const accountEnabled = merged.enabled !== false;
104	    const enabled = baseEnabled && accountEnabled;
105	    const secretResolution = resolveNextcloudTalkSecret(params.cfg, { accountId });
106	    const baseUrl = merged.baseUrl?.trim()?.replace(/\/$/, "") ?? "";
107	
108	    debugAccounts("resolve", {
109	      accountId,
110	      enabled,
111	      secretSource: secretResolution.source,
112	      baseUrl: baseUrl ? "[set]" : "[missing]",
113	    });
114	
115	    return {
116	      accountId,
117	      enabled,
118	      name: merged.name?.trim() || undefined,
119	      baseUrl,
120	      secret: secretResolution.secret,
121	      secretSource: secretResolution.source,
122	      config: merged,
123	    } satisfies ResolvedNextcloudTalkAccount;
124	  };
125	
126	  return resolveAccountWithDefaultFallback({
127	    accountId: params.accountId,
128	    normalizeAccountId,
129	    resolvePrimary: resolve,
130	    hasCredential: (account) => account.secretSource !== "none",
131	    resolveDefaultAccountId: () => resolveDefaultNextcloudTalkAccountId(params.cfg),
132	  });
133	}
134	
135	export function listEnabledNextcloudTalkAccounts(cfg: CoreConfig): ResolvedNextcloudTalkAccount[] {
136	  return listNextcloudTalkAccountIds(cfg)
137	    .map((accountId) => resolveNextcloudTalkAccount({ cfg, accountId }))
138	    .filter((account) => account.enabled);
139	}
