1	/**
2	 * Synology Chat HTTP client.
3	 * Sends messages TO Synology Chat via the incoming webhook URL.
4	 */
5	
6	import * as http from "node:http";
7	import * as https from "node:https";
8	import { safeParseJsonWithSchema, safeParseWithSchema } from "openclaw/plugin-sdk/extension-shared";
9	import { z } from "zod";
10	
11	const MIN_SEND_INTERVAL_MS = 500;
12	let lastSendTime = 0;
13	
14	// --- Chat user_id resolution ---
15	// Synology Chat uses two different user_id spaces:
16	//   - Outgoing webhook user_id: per-integration sequential ID (e.g. 1)
17	//   - Chat API user_id: global internal ID (e.g. 4)
18	// The chatbot API (method=chatbot) requires the Chat API user_id in the
19	// user_ids array. We resolve via the user_list API and cache the result.
20	
21	interface ChatUser {
22	  user_id: number;
23	  username: string;
24	  nickname: string;
25	}
26	
27	type ChatUserCacheEntry = {
28	  users: ChatUser[];
29	  cachedAt: number;
30	};
31	
32	type ChatWebhookPayload = {
33	  text?: string;
34	  file_url?: string;
35	  user_ids?: number[];
36	};
37	
38	const ChatUserSchema = z
39	  .object({
40	    user_id: z.number(),
41	    username: z.string().optional(),
42	    nickname: z.string().optional(),
43	  })
44	  .transform(
45	    (user): ChatUser => ({
46	      user_id: user.user_id,
47	      username: user.username ?? "",
48	      nickname: user.nickname ?? "",
49	    }),
50	  );
51	
52	const ChatUserListResponseSchema = z.object({
53	  success: z.boolean(),
54	  data: z
55	    .object({
56	      users: z
57	        .array(z.unknown())
58	        .optional()
59	        .transform((users) =>
60	          (users ?? []).flatMap((user) => {
61	            const parsed = safeParseWithSchema(ChatUserSchema, user);
62	            return parsed ? [parsed] : [];
63	          }),
64	        ),
65	    })
66	    .optional(),
67	});
68	
69	// Cache user lists per bot endpoint to avoid cross-account bleed.
70	const chatUserCache = new Map<string, ChatUserCacheEntry>();
71	const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
72	
73	/**
74	 * Send a text message to Synology Chat via the incoming webhook.
75	 *
76	 * @param incomingUrl - Synology Chat incoming webhook URL
77	 * @param text - Message text to send
78	 * @param userId - Optional user ID to mention with @
79	 * @returns true if sent successfully
80	 */
81	export async function sendMessage(
82	  incomingUrl: string,
83	  text: string,
84	  userId?: string | number,
85	  allowInsecureSsl = true,
86	): Promise<boolean> {
87	  // Synology Chat API requires user_ids (numeric) to specify the recipient
88	  // The @mention is optional but user_ids is mandatory
89	  const body = buildWebhookBody({ text }, userId);
90	
91	  // Internal rate limit: min 500ms between sends
92	  const now = Date.now();
93	  const elapsed = now - lastSendTime;
94	  if (elapsed < MIN_SEND_INTERVAL_MS) {
95	    await sleep(MIN_SEND_INTERVAL_MS - elapsed);
96	  }
97	
98	  // Retry with exponential backoff (3 attempts, 300ms base)
99	  const maxRetries = 3;
100	  const baseDelay = 300;
101	
102	  for (let attempt = 0; attempt < maxRetries; attempt++) {
103	    try {
104	      const ok = await doPost(incomingUrl, body, allowInsecureSsl);
105	      lastSendTime = Date.now();
106	      if (ok) return true;
107	    } catch {
108	      // will retry
109	    }
110	
111	    if (attempt < maxRetries - 1) {
112	      await sleep(baseDelay * Math.pow(2, attempt));
113	    }
114	  }
115	
116	  return false;
117	}
118	
119	/**
120	 * Send a file URL to Synology Chat.
121	 */
122	export async function sendFileUrl(
123	  incomingUrl: string,
124	  fileUrl: string,
125	  userId?: string | number,
126	  allowInsecureSsl = true,
127	): Promise<boolean> {
128	  const body = buildWebhookBody({ file_url: fileUrl }, userId);
129	
130	  try {
131	    const ok = await doPost(incomingUrl, body, allowInsecureSsl);
132	    lastSendTime = Date.now();
133	    return ok;
134	  } catch {
135	    return false;
136	  }
137	}
138	
139	/**
140	 * Fetch the list of Chat users visible to this bot via the user_list API.
141	 * Results are cached for CACHE_TTL_MS to avoid excessive API calls.
142	 *
143	 * The user_list endpoint uses the same base URL as the chatbot API but
144	 * with method=user_list instead of method=chatbot.
145	 */
146	export async function fetchChatUsers(
147	  incomingUrl: string,
148	  allowInsecureSsl = true,
149	  log?: { warn: (...args: unknown[]) => void },
150	): Promise<ChatUser[]> {
151	  const now = Date.now();
152	  const listUrl = incomingUrl.replace(/method=\w+/, "method=user_list");
153	  const cached = chatUserCache.get(listUrl);
154	  if (cached && now - cached.cachedAt < CACHE_TTL_MS) {
155	    return cached.users;
156	  }
157	
158	  return new Promise((resolve) => {
159	    let parsedUrl: URL;
160	    try {
161	      parsedUrl = new URL(listUrl);
162	    } catch {
163	      log?.warn("fetchChatUsers: invalid user_list URL, using cached data");
164	      resolve(cached?.users ?? []);
165	      return;
166	    }
167	    const transport = parsedUrl.protocol === "https:" ? https : http;
168	
169	    transport
170	      .get(listUrl, { rejectUnauthorized: !allowInsecureSsl } as any, (res) => {
171	        let data = "";
172	        res.on("data", (c: Buffer) => {
173	          data += c.toString();
174	        });
175	        res.on("end", () => {
176	          const result = safeParseJsonWithSchema(ChatUserListResponseSchema, data);
177	          if (!result) {
178	            log?.warn("fetchChatUsers: failed to parse user_list response");
179	            resolve(cached?.users ?? []);
180	            return;
181	          }
182	
183	          if (result.success) {
184	            const users = result.data?.users ?? [];
185	            chatUserCache.set(listUrl, {
186	              users,
187	              cachedAt: now,
188	            });
189	            resolve(users);
190	            return;
191	          }
192	
193	          log?.warn(`fetchChatUsers: API returned success=${result.success}, using cached data`);
194	          resolve(cached?.users ?? []);
195	        });
196	      })
197	      .on("error", (err) => {
198	        log?.warn(`fetchChatUsers: HTTP error — ${err instanceof Error ? err.message : err}`);
199	        resolve(cached?.users ?? []);
200	      });
201	  });
202	}
203	
204	/**
205	 * Resolve a mutable webhook username/nickname to the correct Chat API user_id.
206	 *
207	 * Synology Chat outgoing webhooks send a user_id that may NOT match the
208	 * Chat-internal user_id needed by the chatbot API (method=chatbot).
209	 * The webhook's "username" field corresponds to the Chat user's "nickname".
210	 *
211	 * @returns The correct Chat user_id, or undefined if not found
212	 */
213	export async function resolveLegacyWebhookNameToChatUserId(params: {
214	  incomingUrl: string;
215	  mutableWebhookUsername: string;
216	  allowInsecureSsl?: boolean;
217	  log?: { warn: (...args: unknown[]) => void };
218	}): Promise<number | undefined> {
219	  const users = await fetchChatUsers(params.incomingUrl, params.allowInsecureSsl, params.log);
220	  const lower = params.mutableWebhookUsername.toLowerCase();
221	
222	  // Match by nickname first (webhook "username" field = Chat "nickname")
223	  const byNickname = users.find((u) => u.nickname.toLowerCase() === lower);
224	  if (byNickname) return byNickname.user_id;
225	
226	  // Then by username
227	  const byUsername = users.find((u) => u.username.toLowerCase() === lower);
228	  if (byUsername) return byUsername.user_id;
229	
230	  return undefined;
231	}
232	
233	function buildWebhookBody(payload: ChatWebhookPayload, userId?: string | number): string {
234	  const numericId = parseNumericUserId(userId);
235	  if (numericId !== undefined) {
236	    payload.user_ids = [numericId];
237	  }
238	  return `payload=${encodeURIComponent(JSON.stringify(payload))}`;
239	}
240	
241	function parseNumericUserId(userId?: string | number): number | undefined {
242	  if (userId === undefined) {
243	    return undefined;
244	  }
245	  const numericId = typeof userId === "number" ? userId : parseInt(userId, 10);
246	  return Number.isNaN(numericId) ? undefined : numericId;
247	}
248	
249	function doPost(url: string, body: string, allowInsecureSsl = true): Promise<boolean> {
250	  return new Promise((resolve, reject) => {
251	    let parsedUrl: URL;
252	    try {
253	      parsedUrl = new URL(url);
254	    } catch {
255	      reject(new Error(`Invalid URL: ${url}`));
256	      return;
257	    }
258	    const transport = parsedUrl.protocol === "https:" ? https : http;
259	
260	    const req = transport.request(
261	      url,
262	      {
263	        method: "POST",
264	        headers: {
265	          "Content-Type": "application/x-www-form-urlencoded",
266	          "Content-Length": Buffer.byteLength(body),
267	        },
268	        timeout: 30_000,
269	        // Synology NAS may use self-signed certs on local network.
270	        // Set allowInsecureSsl: true in channel config to skip verification.
271	        rejectUnauthorized: !allowInsecureSsl,
272	      },
273	      (res) => {
274	        let data = "";
275	        res.on("data", (chunk: Buffer) => {
276	          data += chunk.toString();
277	        });
278	        res.on("end", () => {
279	          resolve(res.statusCode === 200);
280	        });
281	      },
282	    );
283	
284	    req.on("error", reject);
285	    req.on("timeout", () => {
286	      req.destroy();
287	      reject(new Error("Request timeout"));
288	    });
289	    req.write(body);
290	    req.end();
291	  });
292	}
293	
294	function sleep(ms: number): Promise<void> {
295	  return new Promise((resolve) => setTimeout(resolve, ms));
296	}
