1	/**
2	 * Security module: token validation, rate limiting, input sanitization, user allowlist.
3	 */
4	
5	import * as crypto from "node:crypto";
6	import {
7	  createFixedWindowRateLimiter,
8	  type FixedWindowRateLimiter,
9	} from "openclaw/plugin-sdk/webhook-ingress";
10	
11	export type DmAuthorizationResult =
12	  | { allowed: true }
13	  | { allowed: false; reason: "disabled" | "allowlist-empty" | "not-allowlisted" };
14	
15	/**
16	 * Validate webhook token using constant-time comparison.
17	 * Prevents timing attacks that could leak token bytes.
18	 */
19	export function validateToken(received: string, expected: string): boolean {
20	  if (!received || !expected) return false;
21	
22	  // Use HMAC to normalize lengths before comparison,
23	  // preventing timing side-channel on token length.
24	  const key = "openclaw-token-cmp";
25	  const a = crypto.createHmac("sha256", key).update(received).digest();
26	  const b = crypto.createHmac("sha256", key).update(expected).digest();
27	
28	  return crypto.timingSafeEqual(a, b);
29	}
30	
31	/**
32	 * Check if a user ID is in the allowed list.
33	 * Allowlist mode must be explicit; empty lists should not match any user.
34	 */
35	export function checkUserAllowed(userId: string, allowedUserIds: string[]): boolean {
36	  if (allowedUserIds.length === 0) return false;
37	  return allowedUserIds.includes(userId);
38	}
39	
40	/**
41	 * Resolve DM authorization for a sender across all DM policy modes.
42	 * Keeps policy semantics in one place so webhook/startup behavior stays consistent.
43	 */
44	export function authorizeUserForDm(
45	  userId: string,
46	  dmPolicy: "open" | "allowlist" | "disabled",
47	  allowedUserIds: string[],
48	): DmAuthorizationResult {
49	  if (dmPolicy === "disabled") {
50	    return { allowed: false, reason: "disabled" };
51	  }
52	  if (dmPolicy === "open") {
53	    return { allowed: true };
54	  }
55	  if (allowedUserIds.length === 0) {
56	    return { allowed: false, reason: "allowlist-empty" };
57	  }
58	  if (!checkUserAllowed(userId, allowedUserIds)) {
59	    return { allowed: false, reason: "not-allowlisted" };
60	  }
61	  return { allowed: true };
62	}
63	
64	/**
65	 * Sanitize user input to prevent prompt injection attacks.
66	 * Filters known dangerous patterns and truncates long messages.
67	 */
68	export function sanitizeInput(text: string): string {
69	  const dangerousPatterns = [
70	    /ignore\s+(all\s+)?(previous|prior|above)\s+(instructions?|prompts?)/gi,
71	    /you\s+are\s+now\s+/gi,
72	    /system:\s*/gi,
73	    /<\|.*?\|>/g, // special tokens
74	  ];
75	
76	  let sanitized = text;
77	  for (const pattern of dangerousPatterns) {
78	    sanitized = sanitized.replace(pattern, "[FILTERED]");
79	  }
80	
81	  const maxLength = 4000;
82	  if (sanitized.length > maxLength) {
83	    sanitized = sanitized.slice(0, maxLength) + "... [truncated]";
84	  }
85	
86	  return sanitized;
87	}
88	
89	/**
90	 * Sliding window rate limiter per user ID.
91	 */
92	export class RateLimiter {
93	  private readonly limiter: FixedWindowRateLimiter;
94	  private readonly limit: number;
95	
96	  constructor(limit = 30, windowSeconds = 60, maxTrackedUsers = 5_000) {
97	    this.limit = limit;
98	    this.limiter = createFixedWindowRateLimiter({
99	      windowMs: Math.max(1, Math.floor(windowSeconds * 1000)),
100	      maxRequests: Math.max(1, Math.floor(limit)),
101	      maxTrackedKeys: Math.max(1, Math.floor(maxTrackedUsers)),
102	    });
103	  }
104	
105	  /** Returns true if the request is allowed, false if rate-limited. */
106	  check(userId: string): boolean {
107	    return !this.limiter.isRateLimited(userId);
108	  }
109	
110	  /** Exposed for tests and diagnostics. */
111	  size(): number {
112	    return this.limiter.size();
113	  }
114	
115	  /** Exposed for tests and account lifecycle cleanup. */
116	  clear(): void {
117	    this.limiter.clear();
118	  }
119	
120	  /** Exposed for tests. */
121	  maxRequests(): number {
122	    return this.limit;
123	  }
124	}
