10	
11	type SynologyGatewayLog = {
12	  info?: (message: string) => void;
13	  warn?: (message: string) => void;
14	  error?: (message: string) => void;
15	};
16	type SynologyGatewayStartupIssueCode =
17	  | "disabled"
18	  | "missing-credentials"
19	  | "empty-allowlist"
20	  | "inherited-shared-webhook-path"
21	  | "duplicate-webhook-path";
22	type SynologyGatewayStartupIssue = {
23	  code: SynologyGatewayStartupIssueCode;
24	  logLevel: "info" | "warn";
25	  message: string;
26	};
27	
28	const activeRouteUnregisters = new Map<string, () => void>();
29	
30	function buildStartupIssue(
31	  code: SynologyGatewayStartupIssueCode,
32	  message: string,
33	  logLevel: "info" | "warn" = "warn",
34	): SynologyGatewayStartupIssue {
35	  return { code, logLevel, message };
36	}
37	
38	function logStartupIssues(
39	  log: SynologyGatewayLog | undefined,
40	  issues: SynologyGatewayStartupIssue[],
41	) {
42	  for (const issue of issues) {
43	    const message = `Synology Chat ${issue.message}`;
44	    if (issue.logLevel === "info") {
45	      log?.info?.(message);
46	      continue;
47	    }
48	    log?.warn?.(message);
49	  }
50	}
