52	function getRouteKey(account: ResolvedSynologyChatAccount): string {
53	  return `${account.accountId}:${account.webhookPath}`;
54	}
55	
56	function createUnknownArgsLogAdapter(
57	  log?: SynologyGatewayLog,
58	): WebhookHandlerDeps["log"] | undefined {
59	  if (!log) {
60	    return undefined;
61	  }
62	  return {
63	    info: (...args) => log.info?.(String(args[0] ?? "")),
64	    warn: (...args) => log.warn?.(String(args[0] ?? "")),
65	    error: (...args) => log.error?.(String(args[0] ?? "")),
66	  };
67	}
68	
69	export function collectSynologyGatewayStartupIssues(params: {
70	  cfg: OpenClawConfig;
71	  account: ResolvedSynologyChatAccount;
72	  accountId: string;
73	}): SynologyGatewayStartupIssue[] {
74	  const { cfg, account, accountId } = params;
75	  const issues: SynologyGatewayStartupIssue[] = [];
76	
77	  if (!account.enabled) {
78	    issues.push(
79	      buildStartupIssue("disabled", `account ${accountId} is disabled, skipping`, "info"),
80	    );
81	    return issues;
82	  }
83	  if (!account.token || !account.incomingUrl) {
84	    issues.push(
85	      buildStartupIssue(
86	        "missing-credentials",
87	        `account ${accountId} not fully configured (missing token or incomingUrl)`,
88	      ),
89	    );
90	  }
91	  if (account.dmPolicy === "allowlist" && account.allowedUserIds.length === 0) {
92	    issues.push(
93	      buildStartupIssue(
94	        "empty-allowlist",
95	        `account ${accountId} has dmPolicy=allowlist but empty allowedUserIds; refusing to start route`,
96	      ),
97	    );
98	  }
99	
100	  const accountIds = listAccountIds(cfg);
101	  const isMultiAccount = accountIds.length > 1;
102	  if (
103	    isMultiAccount &&
104	    accountId !== DEFAULT_ACCOUNT_ID &&
105	    account.webhookPathSource === "inherited-base" &&
106	    !account.dangerouslyAllowInheritedWebhookPath
107	  ) {
108	    issues.push(
109	      buildStartupIssue(
110	        "inherited-shared-webhook-path",
111	        `account ${accountId} must set an explicit webhookPath in multi-account setups; refusing inherited shared path. Set channels.synology-chat.accounts.${accountId}.webhookPath or opt in with dangerouslyAllowInheritedWebhookPath=true.`,
112	      ),
113	    );
114	  }
115	
116	  const conflictingAccounts = accountIds.filter((candidateId) => {
117	    if (candidateId === accountId) {
118	      return false;
119	    }
120	    const candidate = resolveAccount(cfg, candidateId);
121	    return candidate.enabled && candidate.webhookPath === account.webhookPath;
122	  });
123	  if (conflictingAccounts.length > 0) {
124	    issues.push(
125	      buildStartupIssue(
126	        "duplicate-webhook-path",
127	        `account ${accountId} conflicts on webhookPath ${account.webhookPath} with ${conflictingAccounts.join(", ")}; refusing to start ambiguous shared route.`,
128	      ),
129	    );
130	  }
131	
132	  return issues;
133	}
134	
135	export function collectSynologyGatewayRoutingWarnings(params: {
136	  cfg: OpenClawConfig;
137	  account: ResolvedSynologyChatAccount;
138	}): string[] {
139	  return collectSynologyGatewayStartupIssues({
140	    cfg: params.cfg,
141	    account: params.account,
142	    accountId: params.account.accountId,
143	  })
144	    .filter(
145	      (issue) =>
146	        issue.code === "inherited-shared-webhook-path" || issue.code === "duplicate-webhook-path",
147	    )
148	    .map((issue) => `- Synology Chat: ${issue.message}`);
149	}
150	
151	export function validateSynologyGatewayAccountStartup(params: {
152	  cfg: OpenClawConfig;
153	  account: ResolvedSynologyChatAccount;
154	  accountId: string;
155	  log?: SynologyGatewayLog;
156	}): { ok: true } | { ok: false } {
157	  const issues = collectSynologyGatewayStartupIssues(params);
158	  if (issues.length > 0) {
159	    logStartupIssues(params.log, issues);
160	    return { ok: false };
161	  }
162	  return { ok: true };
163	}
164	
165	export function registerSynologyWebhookRoute(params: {
166	  account: ResolvedSynologyChatAccount;
167	  accountId: string;
168	  log?: SynologyGatewayLog;
169	}): () => void {
170	  const { account, log } = params;
171	  const routeKey = getRouteKey(account);
172	  const prevUnregister = activeRouteUnregisters.get(routeKey);
173	  if (prevUnregister) {
174	    log?.info?.(`Deregistering stale route before re-registering: ${account.webhookPath}`);
175	    prevUnregister();
176	    activeRouteUnregisters.delete(routeKey);
177	  }
178	
179	  const handler = createWebhookHandler({
180	    account,
181	    deliver: async (msg) =>
182	      await dispatchSynologyChatInboundTurn({
183	        account,
184	        msg,
185	        log: createUnknownArgsLogAdapter(log),
186	      }),
187	    log: createUnknownArgsLogAdapter(log),
188	  });
189	  const unregister = registerPluginHttpRoute({
190	    path: account.webhookPath,
191	    auth: "plugin",
192	    pluginId: CHANNEL_ID,
193	    accountId: account.accountId,
194	    log: (msg: string) => log?.info?.(msg),
195	    handler,
196	  });
197	  activeRouteUnregisters.set(routeKey, unregister);
198	  return () => {
199	    unregister();
200	    activeRouteUnregisters.delete(routeKey);
201	  };
202	}
