568	export function createWebhookHandler(deps: WebhookHandlerDeps) {
569	  const { account, deliver, log } = deps;
570	  const rateLimiter = getRateLimiter(account);
571	  const invalidTokenRateLimiter = getInvalidTokenRateLimiter(account);
572	
573	  return async (req: IncomingMessage, res: ServerResponse) => {
574	    // Only accept POST
575	    if (req.method !== "POST") {
576	      respondJson(res, 405, { error: "Method not allowed" });
577	      return;
578	    }
579	    const requestLifecycle = beginWebhookRequestPipelineOrReject({
580	      req,
581	      res,
582	      inFlightLimiter: webhookInFlightLimiter,
583	      inFlightKey: getSynologyWebhookInFlightKey(account),
584	    });
585	    if (!requestLifecycle.ok) {
586	      return;
587	    }
588	
589	    let authorized: Awaited<ReturnType<typeof parseAndAuthorizeSynologyWebhook>>;
590	    try {
591	      authorized = await parseAndAuthorizeSynologyWebhook({
592	        req,
593	        res,
594	        account,
595	        invalidTokenRateLimiter,
596	        rateLimiter,
597	        log,
598	      });
599	    } finally {
600	      // Only bound the pre-auth request pipeline; async reply delivery is outside webhook ingress.
601	      requestLifecycle.release();
602	    }
603	    if (!authorized.ok) {
604	      return;
605	    }
606	
607	    log?.info(
608	      `Message from ${authorized.message.payload.username} (${authorized.message.payload.user_id}): ${authorized.message.preview}`,
609	    );
610	
611	    // ACK immediately so Synology Chat won't remain in "Processing..."
612	    respondNoContent(res);
613	    await processAuthorizedSynologyWebhook({
614	      account,
615	      deliver,
616	      log,
617	      message: authorized.message,
618	    });
619	  };
620	}
