105	    (account) =>
106	      account.dangerouslyAllowNameMatching &&
107	      "- Synology Chat: dangerouslyAllowNameMatching=true re-enables mutable username/nickname recipient matching for replies. Prefer stable numeric user IDs.",
108	    (account) =>
