1	/**
2	 * Account resolution: reads config from channels.synology-chat,
3	 * merges per-account overrides, falls back to environment variables.
4	 */
5	
6	import {
7	  DEFAULT_ACCOUNT_ID,
8	  listCombinedAccountIds,
9	  resolveMergedAccountConfig,
10	  type OpenClawConfig,
11	} from "openclaw/plugin-sdk/account-resolution";
12	import { resolveDangerousNameMatchingEnabled } from "openclaw/plugin-sdk/config-runtime";
13	import type {
14	  SynologyChatChannelConfig,
15	  ResolvedSynologyChatAccount,
16	  SynologyWebhookPathSource,
17	} from "./types.js";
18	
19	/** Extract the channel config from the full OpenClaw config object. */
20	function getChannelConfig(cfg: OpenClawConfig): SynologyChatChannelConfig | undefined {
21	  return cfg?.channels?.["synology-chat"];
22	}
23	
24	function resolveImplicitAccountId(channelCfg: SynologyChatChannelConfig): string | undefined {
25	  return channelCfg.token || process.env.SYNOLOGY_CHAT_TOKEN ? DEFAULT_ACCOUNT_ID : undefined;
26	}
27	
28	function getRawAccountConfig(
29	  channelCfg: SynologyChatChannelConfig,
30	  accountId: string,
31	): SynologyChatChannelConfig {
32	  if (accountId === DEFAULT_ACCOUNT_ID) {
33	    return channelCfg;
34	  }
35	  return channelCfg.accounts?.[accountId] ?? {};
36	}
37	
38	function hasExplicitWebhookPath(rawAccount: SynologyChatChannelConfig | undefined): boolean {
39	  return typeof rawAccount?.webhookPath === "string" && rawAccount.webhookPath.trim().length > 0;
40	}
41	
42	function resolveWebhookPathSource(params: {
43	  accountId: string;
44	  channelCfg: SynologyChatChannelConfig;
45	  rawAccount: SynologyChatChannelConfig;
46	}): SynologyWebhookPathSource {
47	  if (hasExplicitWebhookPath(params.rawAccount)) {
48	    return "explicit";
49	  }
50	  if (params.accountId !== DEFAULT_ACCOUNT_ID && hasExplicitWebhookPath(params.channelCfg)) {
51	    return "inherited-base";
52	  }
53	  return "default";
54	}
55	
56	/** Parse allowedUserIds from string or array to string[]. */
57	function parseAllowedUserIds(raw: string | string[] | undefined): string[] {
58	  if (!raw) return [];
59	  if (Array.isArray(raw)) return raw.filter(Boolean);
60	  return raw
61	    .split(",")
62	    .map((s) => s.trim())
63	    .filter(Boolean);
64	}
65	
66	function parseRateLimitPerMinute(raw: string | undefined): number {
67	  if (raw == null) {
68	    return 30;
69	  }
70	  const trimmed = raw.trim();
71	  if (!/^-?\d+$/.test(trimmed)) {
72	    return 30;
73	  }
74	  return Number.parseInt(trimmed, 10);
75	}
76	
77	/**
78	 * List all configured account IDs for this channel.
79	 * Returns ["default"] if there's a base config, plus any named accounts.
80	 */
81	export function listAccountIds(cfg: OpenClawConfig): string[] {
82	  const channelCfg = getChannelConfig(cfg);
83	  if (!channelCfg) {
84	    return [];
85	  }
86	
87	  return listCombinedAccountIds({
88	    configuredAccountIds: Object.keys(channelCfg.accounts ?? {}),
89	    implicitAccountId: resolveImplicitAccountId(channelCfg),
90	  });
91	}
92	
93	/**
94	 * Resolve a specific account by ID with full defaults applied.
95	 * Falls back to env vars for the "default" account.
96	 */
97	export function resolveAccount(
98	  cfg: OpenClawConfig,
99	  accountId?: string | null,
100	): ResolvedSynologyChatAccount {
101	  const channelCfg = getChannelConfig(cfg) ?? {};
102	  const id = accountId || DEFAULT_ACCOUNT_ID;
103	  const accountOverrides =
104	    id === DEFAULT_ACCOUNT_ID ? undefined : (channelCfg.accounts?.[id] ?? undefined);
105	  const rawAccount = getRawAccountConfig(channelCfg, id);
106	  const merged = resolveMergedAccountConfig<Record<string, unknown> & SynologyChatChannelConfig>({
107	    channelConfig: channelCfg as Record<string, unknown> & SynologyChatChannelConfig,
108	    accounts: channelCfg.accounts as
109	      | Record<string, Partial<Record<string, unknown> & SynologyChatChannelConfig>>
110	      | undefined,
111	    accountId: id,
112	  });
113	
114	  // Env var fallbacks (primarily for the "default" account)
115	  const envToken = process.env.SYNOLOGY_CHAT_TOKEN ?? "";
116	  const envIncomingUrl = process.env.SYNOLOGY_CHAT_INCOMING_URL ?? "";
117	  const envNasHost = process.env.SYNOLOGY_NAS_HOST ?? "localhost";
118	  const envAllowedUserIds = process.env.SYNOLOGY_ALLOWED_USER_IDS ?? "";
119	  const envRateLimitValue = parseRateLimitPerMinute(process.env.SYNOLOGY_RATE_LIMIT);
120	  const envBotName = process.env.OPENCLAW_BOT_NAME ?? "OpenClaw";
121	  const webhookPathSource = resolveWebhookPathSource({ accountId: id, channelCfg, rawAccount });
122	  const dangerouslyAllowInheritedWebhookPath =
123	    rawAccount.dangerouslyAllowInheritedWebhookPath ??
124	    channelCfg.dangerouslyAllowInheritedWebhookPath ??
125	    false;
126	
127	  // Merge: account override > base channel config > env var
128	  return {
129	    accountId: id,
130	    enabled: merged.enabled ?? true,
131	    token: merged.token ?? envToken,
132	    incomingUrl: merged.incomingUrl ?? envIncomingUrl,
133	    nasHost: merged.nasHost ?? envNasHost,
134	    webhookPath: merged.webhookPath ?? "/webhook/synology",
135	    webhookPathSource,
136	    dangerouslyAllowNameMatching: resolveDangerousNameMatchingEnabled({
