1	/**
2	 * Inbound webhook handler for Synology Chat outgoing webhooks.
3	 * Parses form-urlencoded/JSON body, validates security, delivers to agent.
4	 */
5	
6	import type { IncomingMessage, ServerResponse } from "node:http";
7	import * as querystring from "node:querystring";
8	import {
9	  beginWebhookRequestPipelineOrReject,
10	  createWebhookInFlightLimiter,
11	  isRequestBodyLimitError,
12	  readRequestBodyWithLimit,
13	  requestBodyErrorToText,
14	} from "openclaw/plugin-sdk/webhook-ingress";
15	import * as synologyClient from "./client.js";
16	import { validateToken, authorizeUserForDm, sanitizeInput, RateLimiter } from "./security.js";
17	import type { SynologyWebhookPayload, ResolvedSynologyChatAccount } from "./types.js";
18	
19	// One rate limiter per account, created lazily
20	const rateLimiters = new Map<string, RateLimiter>();
21	const invalidTokenRateLimiters = new Map<string, InvalidTokenRateLimiter>();
22	const webhookInFlightLimiter = createWebhookInFlightLimiter();
23	const PREAUTH_MAX_BODY_BYTES = 64 * 1024;
24	const PREAUTH_BODY_TIMEOUT_MS = 5_000;
25	const PREAUTH_MAX_REQUESTS_PER_MINUTE = 10;
26	const INVALID_TOKEN_WINDOW_MS = 60_000;
27	const INVALID_TOKEN_MAX_TRACKED_KEYS = 5_000;
28	
29	type InvalidTokenRateLimitState = {
30	  count: number;
31	  windowStartMs: number;
32	};
33	
34	class InvalidTokenRateLimiter {
35	  private readonly limit: number;
36	  private readonly state = new Map<string, InvalidTokenRateLimitState>();
37	
38	  constructor(limit: number) {
39	    this.limit = limit;
40	  }
41	
42	  private normalizeState(key: string, nowMs: number): InvalidTokenRateLimitState | undefined {
43	    const existing = this.state.get(key);
44	    if (!existing) {
45	      return undefined;
46	    }
47	    if (nowMs - existing.windowStartMs >= INVALID_TOKEN_WINDOW_MS) {
48	      this.state.delete(key);
49	      return undefined;
50	    }
51	    return existing;
52	  }
53	
54	  private touch(key: string, value: InvalidTokenRateLimitState): void {
55	    this.state.delete(key);
56	    this.state.set(key, value);
57	    while (this.state.size > INVALID_TOKEN_MAX_TRACKED_KEYS) {
58	      const oldestKey = this.state.keys().next().value;
59	      if (!oldestKey) {
60	        break;
61	      }
62	      this.state.delete(oldestKey);
63	    }
64	  }
65	
66	  isLocked(key: string, nowMs = Date.now()): boolean {
67	    if (!key) {
68	      return false;
69	    }
70	    const existing = this.normalizeState(key, nowMs);
71	    return (existing?.count ?? 0) > this.limit;
72	  }
73	
74	  recordFailure(key: string, nowMs = Date.now()): boolean {
75	    if (!key) {
76	      return false;
77	    }
78	    const existing = this.normalizeState(key, nowMs);
79	    const nextCount = (existing?.count ?? 0) + 1;
80	    const windowStartMs = existing?.windowStartMs ?? nowMs;
81	    this.touch(key, { count: nextCount, windowStartMs });
82	    return nextCount > this.limit;
83	  }
84	
85	  clear(): void {
86	    this.state.clear();
87	  }
88	
89	  maxRequests(): number {
90	    return this.limit;
91	  }
92	}
93	
94	function getRateLimiter(account: ResolvedSynologyChatAccount): RateLimiter {
95	  let rl = rateLimiters.get(account.accountId);
96	  if (!rl || rl.maxRequests() !== account.rateLimitPerMinute) {
97	    rl?.clear();
98	    rl = new RateLimiter(account.rateLimitPerMinute);
99	    rateLimiters.set(account.accountId, rl);
100	  }
101	  return rl;
102	}
103	
104	function getInvalidTokenRateLimiter(account: ResolvedSynologyChatAccount): InvalidTokenRateLimiter {
105	  const limit = Math.min(account.rateLimitPerMinute, PREAUTH_MAX_REQUESTS_PER_MINUTE);
106	  let rl = invalidTokenRateLimiters.get(account.accountId);
107	  if (!rl || rl.maxRequests() !== limit) {
108	    rl?.clear();
109	    rl = new InvalidTokenRateLimiter(limit);
110	    invalidTokenRateLimiters.set(account.accountId, rl);
111	  }
112	  return rl;
113	}
114	
115	export function clearSynologyWebhookRateLimiterStateForTest(): void {
116	  for (const limiter of rateLimiters.values()) {
117	    limiter.clear();
118	  }
119	  rateLimiters.clear();
120	  for (const limiter of invalidTokenRateLimiters.values()) {
121	    limiter.clear();
122	  }
123	  invalidTokenRateLimiters.clear();
124	  webhookInFlightLimiter.clear();
125	}
126	
127	export function getSynologyWebhookRateLimiterCountForTest(): number {
128	  return rateLimiters.size + invalidTokenRateLimiters.size;
129	}
130	
131	function getSynologyWebhookInvalidTokenRateLimitKey(req: IncomingMessage): string {
132	  return req.socket?.remoteAddress ?? "unknown";
133	}
134	
135	function getSynologyWebhookInFlightKey(account: ResolvedSynologyChatAccount): string {
136	  // Synology webhook ingress is typically a single upstream per account, and this
137	  // handler does not have a trusted-proxy-aware client IP config. Keep the shared
138	  // pre-auth concurrency budget scoped per account instead of keying on a fragile
139	  // remoteAddress value that can collapse behind proxies or to "unknown".
140	  return account.accountId;
141	}
142	
143	/** Read the full request body as a string. */
144	async function readBody(req: IncomingMessage): Promise<
145	  | { ok: true; body: string }
146	  | {
147	      ok: false;
148	      statusCode: number;
149	      error: string;
150	    }
151	> {
152	  try {
153	    const body = await readRequestBodyWithLimit(req, {
154	      maxBytes: PREAUTH_MAX_BODY_BYTES,
155	      timeoutMs: PREAUTH_BODY_TIMEOUT_MS,
156	    });
157	    return { ok: true, body };
158	  } catch (err) {
159	    if (isRequestBodyLimitError(err)) {
160	      return {
161	        ok: false,
162	        statusCode: err.statusCode,
163	        error: requestBodyErrorToText(err.code),
164	      };
165	    }
166	    return {
167	      ok: false,
168	      statusCode: 400,
169	      error: "Invalid request body",
170	    };
171	  }
172	}
173	
174	function firstNonEmptyString(value: unknown): string | undefined {
175	  if (Array.isArray(value)) {
176	    for (const item of value) {
177	      const normalized = firstNonEmptyString(item);
178	      if (normalized) return normalized;
179	    }
180	    return undefined;
181	  }
182	  if (value === null || value === undefined) return undefined;
183	  const str = String(value).trim();
184	  return str.length > 0 ? str : undefined;
185	}
186	
187	function pickAlias(record: Record<string, unknown>, aliases: string[]): string | undefined {
188	  for (const alias of aliases) {
189	    const normalized = firstNonEmptyString(record[alias]);
190	    if (normalized) return normalized;
191	  }
192	  return undefined;
193	}
194	
195	function parseQueryParams(req: IncomingMessage): Record<string, unknown> {
196	  try {
197	    const url = new URL(req.url ?? "", "http://localhost");
198	    const out: Record<string, unknown> = {};
199	    for (const [key, value] of url.searchParams.entries()) {
200	      out[key] = value;
201	    }
202	    return out;
203	  } catch {
204	    return {};
205	  }
206	}
207	
208	function parseFormBody(body: string): Record<string, unknown> {
209	  return querystring.parse(body) as Record<string, unknown>;
210	}
211	
212	function parseJsonBody(body: string): Record<string, unknown> {
213	  if (!body.trim()) return {};
214	  const parsed = JSON.parse(body);
215	  if (!parsed || Array.isArray(parsed) || typeof parsed !== "object") {
216	    throw new Error("Invalid JSON body");
217	  }
218	  return parsed as Record<string, unknown>;
219	}
220	
221	function headerValue(header: string | string[] | undefined): string | undefined {
222	  return firstNonEmptyString(header);
223	}
224	
225	function extractTokenFromHeaders(req: IncomingMessage): string | undefined {
226	  const explicit =
227	    headerValue(req.headers["x-synology-token"]) ??
228	    headerValue(req.headers["x-webhook-token"]) ??
229	    headerValue(req.headers["x-openclaw-token"]);
230	  if (explicit) return explicit;
231	
232	  const auth = headerValue(req.headers.authorization);
233	  if (!auth) return undefined;
234	
235	  const bearerMatch = auth.match(/^Bearer\s+(.+)$/i);
236	  if (bearerMatch?.[1]) return bearerMatch[1].trim();
237	  return auth.trim();
238	}
239	
240	/**
241	 * Parse/normalize incoming webhook payload.
242	 *
243	 * Supports:
244	 * - application/x-www-form-urlencoded
245	 * - application/json
246	 *
247	 * Token resolution order: body.token -> query.token -> headers
248	 * Field aliases:
249	 * - user_id <- user_id | userId | user
250	 * - text    <- text | message | content
251	 */
252	function parsePayload(req: IncomingMessage, body: string): SynologyWebhookPayload | null {
253	  const contentType = String(req.headers["content-type"] ?? "").toLowerCase();
254	
255	  let bodyFields: Record<string, unknown> = {};
256	  if (contentType.includes("application/json")) {
257	    bodyFields = parseJsonBody(body);
258	  } else if (contentType.includes("application/x-www-form-urlencoded")) {
259	    bodyFields = parseFormBody(body);
260	  } else {
261	    // Fallback for clients with missing/incorrect content-type.
262	    // Try JSON first, then form-urlencoded.
263	    try {
264	      bodyFields = parseJsonBody(body);
265	    } catch {
266	      bodyFields = parseFormBody(body);
267	    }
268	  }
269	
270	  const queryFields = parseQueryParams(req);
271	  const headerToken = extractTokenFromHeaders(req);
272	
273	  const token =
274	    pickAlias(bodyFields, ["token"]) ?? pickAlias(queryFields, ["token"]) ?? headerToken;
275	  const userId =
276	    pickAlias(bodyFields, ["user_id", "userId", "user"]) ??
277	    pickAlias(queryFields, ["user_id", "userId", "user"]);
278	  const text =
279	    pickAlias(bodyFields, ["text", "message", "content"]) ??
280	    pickAlias(queryFields, ["text", "message", "content"]);
281	
282	  if (!token || !userId || !text) return null;
283	
284	  return {
285	    token,
286	    channel_id:
287	      pickAlias(bodyFields, ["channel_id"]) ?? pickAlias(queryFields, ["channel_id"]) ?? undefined,
288	    channel_name:
289	      pickAlias(bodyFields, ["channel_name"]) ??
290	      pickAlias(queryFields, ["channel_name"]) ??
291	      undefined,
292	    user_id: userId,
293	    username:
294	      pickAlias(bodyFields, ["username", "user_name", "name"]) ??
295	      pickAlias(queryFields, ["username", "user_name", "name"]) ??
296	      "unknown",
297	    post_id: pickAlias(bodyFields, ["post_id"]) ?? pickAlias(queryFields, ["post_id"]) ?? undefined,
298	    timestamp:
299	      pickAlias(bodyFields, ["timestamp"]) ?? pickAlias(queryFields, ["timestamp"]) ?? undefined,
300	    text,
301	    trigger_word:
302	      pickAlias(bodyFields, ["trigger_word", "triggerWord"]) ??
303	      pickAlias(queryFields, ["trigger_word", "triggerWord"]) ??
304	      undefined,
305	  };
306	}
307	
308	/** Send a JSON response. */
309	function respondJson(res: ServerResponse, statusCode: number, body: Record<string, unknown>) {
310	  res.writeHead(statusCode, { "Content-Type": "application/json" });
311	  res.end(JSON.stringify(body));
312	}
313	
314	/** Send a no-content ACK. */
315	function respondNoContent(res: ServerResponse) {
316	  res.writeHead(204);
317	  res.end();
318	}
319	
320	export interface WebhookHandlerDeps {
321	  account: ResolvedSynologyChatAccount;
322	  deliver: (msg: import("./inbound-context.js").SynologyInboundMessage) => Promise<string | null>;
323	  log?: {
324	    info: (...args: unknown[]) => void;
325	    warn: (...args: unknown[]) => void;
326	    error: (...args: unknown[]) => void;
327	  };
328	}
329	
330	/**
331	 * Create an HTTP request handler for Synology Chat outgoing webhooks.
332	 *
333	 * This handler:
334	 * 1. Parses form-urlencoded/JSON payload
335	 * 2. Validates token (constant-time)
336	 * 3. Checks user allowlist
337	 * 4. Checks rate limit
338	 * 5. Sanitizes input
339	 * 6. Immediately ACKs request (204)
340	 * 7. Delivers to the agent asynchronously and sends final reply via incomingUrl
341	 */
342	type SynologyWebhookAuthorization =
343	  | { ok: false; statusCode: number; error: string }
344	  | { ok: true; commandAuthorized: boolean };
345	
346	type AuthorizedSynologyWebhook = {
347	  payload: SynologyWebhookPayload;
348	  body: string;
349	  commandAuthorized: boolean;
350	  preview: string;
351	};
352	
353	async function parseWebhookPayloadRequest(params: {
354	  req: IncomingMessage;
355	  res: ServerResponse;
356	  log?: WebhookHandlerDeps["log"];
357	}): Promise<{ ok: false } | { ok: true; payload: SynologyWebhookPayload }> {
358	  const bodyResult = await readBody(params.req);
359	  if (!bodyResult.ok) {
360	    params.log?.error("Failed to read request body", bodyResult.error);
361	    respondJson(params.res, bodyResult.statusCode, { error: bodyResult.error });
362	    return { ok: false };
363	  }
364	
365	  let payload: SynologyWebhookPayload | null = null;
366	  try {
367	    payload = parsePayload(params.req, bodyResult.body);
368	  } catch (err) {
369	    params.log?.warn("Failed to parse webhook payload", err);
370	    respondJson(params.res, 400, { error: "Invalid request body" });
371	    return { ok: false };
372	  }
373	  if (!payload) {
374	    respondJson(params.res, 400, { error: "Missing required fields (token, user_id, text)" });
375	    return { ok: false };
376	  }
377	  return { ok: true, payload };
378	}
379	
380	function authorizeSynologyWebhook(params: {
381	  req: IncomingMessage;
382	  account: ResolvedSynologyChatAccount;
383	  payload: SynologyWebhookPayload;
384	  invalidTokenRateLimiter: InvalidTokenRateLimiter;
385	  rateLimiter: RateLimiter;
386	  log?: WebhookHandlerDeps["log"];
387	}): SynologyWebhookAuthorization {
388	  const invalidTokenRateLimitKey = getSynologyWebhookInvalidTokenRateLimitKey(params.req);
389	  // Once a source has exhausted its invalid-token budget, reject all requests in the window.
390	  if (params.invalidTokenRateLimiter.isLocked(invalidTokenRateLimitKey)) {
391	    params.log?.warn(`Rate limit exceeded for remote IP: ${invalidTokenRateLimitKey}`);
392	    return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
393	  }
394	
395	  if (!validateToken(params.payload.token, params.account.token)) {
396	    if (params.invalidTokenRateLimiter.recordFailure(invalidTokenRateLimitKey)) {
397	      params.log?.warn(`Rate limit exceeded for remote IP: ${invalidTokenRateLimitKey}`);
398	      return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
399	    }
400	    params.log?.warn(`Invalid token from ${params.req.socket?.remoteAddress}`);
401	    return { ok: false, statusCode: 401, error: "Invalid token" };
402	  }
403	
404	  const auth = authorizeUserForDm(
405	    params.payload.user_id,
406	    params.account.dmPolicy,
407	    params.account.allowedUserIds,
408	  );
409	  if (!auth.allowed) {
410	    if (auth.reason === "disabled") {
411	      return { ok: false, statusCode: 403, error: "DMs are disabled" };
412	    }
413	    if (auth.reason === "allowlist-empty") {
414	      params.log?.warn(
415	        "Synology Chat allowlist is empty while dmPolicy=allowlist; rejecting message",
416	      );
417	      return {
418	        ok: false,
419	        statusCode: 403,
420	        error: "Allowlist is empty. Configure allowedUserIds or use dmPolicy=open.",
421	      };
422	    }
423	    params.log?.warn(`Unauthorized user: ${params.payload.user_id}`);
424	    return { ok: false, statusCode: 403, error: "User not authorized" };
425	  }
426	
427	  if (!params.rateLimiter.check(params.payload.user_id)) {
428	    // Keep a separate post-auth budget so authenticated users are still throttled per sender.
429	    params.log?.warn(`Rate limit exceeded for user: ${params.payload.user_id}`);
430	    return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
431	  }
432	
433	  return { ok: true, commandAuthorized: auth.allowed };
434	}
435	
436	function sanitizeSynologyWebhookText(payload: SynologyWebhookPayload): string {
437	  let cleanText = sanitizeInput(payload.text);
438	  if (payload.trigger_word && cleanText.startsWith(payload.trigger_word)) {
439	    cleanText = cleanText.slice(payload.trigger_word.length).trim();
440	  }
441	  return cleanText;
442	}
443	
444	async function parseAndAuthorizeSynologyWebhook(params: {
445	  req: IncomingMessage;
446	  res: ServerResponse;
447	  account: ResolvedSynologyChatAccount;
448	  invalidTokenRateLimiter: InvalidTokenRateLimiter;
449	  rateLimiter: RateLimiter;
450	  log?: WebhookHandlerDeps["log"];
451	}): Promise<{ ok: false } | { ok: true; message: AuthorizedSynologyWebhook }> {
452	  const parsed = await parseWebhookPayloadRequest(params);
453	  if (!parsed.ok) {
454	    return { ok: false };
455	  }
456	
457	  const authorized = authorizeSynologyWebhook({
458	    req: params.req,
459	    account: params.account,
460	    payload: parsed.payload,
461	    invalidTokenRateLimiter: params.invalidTokenRateLimiter,
462	    rateLimiter: params.rateLimiter,
463	    log: params.log,
464	  });
465	  if (!authorized.ok) {
466	    respondJson(params.res, authorized.statusCode, { error: authorized.error });
467	    return { ok: false };
468	  }
469	
470	  const cleanText = sanitizeSynologyWebhookText(parsed.payload);
471	  if (!cleanText) {
472	    respondNoContent(params.res);
473	    return { ok: false };
474	  }
475	  const preview = cleanText.length > 100 ? `${cleanText.slice(0, 100)}...` : cleanText;
476	  return {
477	    ok: true,
478	    message: {
479	      payload: parsed.payload,
480	      body: cleanText,
481	      commandAuthorized: authorized.commandAuthorized,
482	      preview,
483	    },
484	  };
485	}
486	
487	async function resolveSynologyReplyDeliveryUserId(params: {
488	  account: ResolvedSynologyChatAccount;
489	  payload: SynologyWebhookPayload;
490	  log?: WebhookHandlerDeps["log"];
491	}): Promise<string> {
492	  if (!params.account.dangerouslyAllowNameMatching) {
493	    return params.payload.user_id;
494	  }
495	
496	  const resolvedChatApiUserId = await synologyClient.resolveLegacyWebhookNameToChatUserId({
497	    incomingUrl: params.account.incomingUrl,
498	    mutableWebhookUsername: params.payload.username,
499	    allowInsecureSsl: params.account.allowInsecureSsl,
500	    log: params.log,
501	  });
502	  if (resolvedChatApiUserId !== undefined) {
503	    return String(resolvedChatApiUserId);
504	  }
505	  params.log?.warn(
506	    `Could not resolve Chat API user_id for "${params.payload.username}" — falling back to webhook user_id ${params.payload.user_id}. Reply delivery may fail.`,
507	  );
508	  return params.payload.user_id;
509	}
510	
511	async function processAuthorizedSynologyWebhook(params: {
512	  account: ResolvedSynologyChatAccount;
513	  deliver: WebhookHandlerDeps["deliver"];
514	  log?: WebhookHandlerDeps["log"];
515	  message: AuthorizedSynologyWebhook;
516	}): Promise<void> {
517	  const authorizedWebhookUserId = params.message.payload.user_id;
518	  let deliveryUserId = authorizedWebhookUserId;
519	  try {
520	    deliveryUserId = await resolveSynologyReplyDeliveryUserId({
521	      account: params.account,
522	      payload: params.message.payload,
523	      log: params.log,
524	    });
525	
526	    const deliverPromise = params.deliver({
527	      body: params.message.body,
528	      from: authorizedWebhookUserId,
529	      senderName: params.message.payload.username,
530	      provider: "synology-chat",
531	      chatType: "direct",
532	      accountId: params.account.accountId,
533	      commandAuthorized: params.message.commandAuthorized,
534	      chatUserId: deliveryUserId,
535	    });
536	    const timeoutPromise = new Promise<null>((_, reject) =>
537	      setTimeout(() => reject(new Error("Agent response timeout (120s)")), 120_000),
538	    );
539	    const reply = await Promise.race([deliverPromise, timeoutPromise]);
540	    if (!reply) {
541	      return;
542	    }
543	
544	    await synologyClient.sendMessage(
545	      params.account.incomingUrl,
546	      reply,
547	      deliveryUserId,
548	      params.account.allowInsecureSsl,
549	    );
550	    const replyPreview = reply.length > 100 ? `${reply.slice(0, 100)}...` : reply;
551	    params.log?.info?.(
552	      `Reply sent to ${params.message.payload.username} (${deliveryUserId}): ${replyPreview}`,
553	    );
554	  } catch (err) {
555	    const errMsg = err instanceof Error ? `${err.message}\n${err.stack}` : String(err);
556	    params.log?.error?.(
557	      `Failed to process message from ${params.message.payload.username}: ${errMsg}`,
558	    );
559	    await synologyClient.sendMessage(
560	      params.account.incomingUrl,
561	      "Sorry, an error occurred while processing your message.",
562	      deliveryUserId,
563	      params.account.allowInsecureSsl,
564	    );
565	  }
566	}
567	
568	export function createWebhookHandler(deps: WebhookHandlerDeps) {
569	  const { account, deliver, log } = deps;
570	  const rateLimiter = getRateLimiter(account);
571	  const invalidTokenRateLimiter = getInvalidTokenRateLimiter(account);
572	
573	  return async (req: IncomingMessage, res: ServerResponse) => {
574	    // Only accept POST
575	    if (req.method !== "POST") {
576	      respondJson(res, 405, { error: "Method not allowed" });
577	      return;
578	    }
579	    const requestLifecycle = beginWebhookRequestPipelineOrReject({
580	      req,
581	      res,
582	      inFlightLimiter: webhookInFlightLimiter,
583	      inFlightKey: getSynologyWebhookInFlightKey(account),
584	    });
585	    if (!requestLifecycle.ok) {
586	      return;
587	    }
588	
589	    let authorized: Awaited<ReturnType<typeof parseAndAuthorizeSynologyWebhook>>;
590	    try {
591	      authorized = await parseAndAuthorizeSynologyWebhook({
592	        req,
593	        res,
594	        account,
595	        invalidTokenRateLimiter,
596	        rateLimiter,
597	        log,
598	      });
599	    } finally {
600	      // Only bound the pre-auth request pipeline; async reply delivery is outside webhook ingress.
601	      requestLifecycle.release();
602	    }
603	    if (!authorized.ok) {
604	      return;
605	    }
606	
607	    log?.info(
608	      `Message from ${authorized.message.payload.username} (${authorized.message.payload.user_id}): ${authorized.message.preview}`,
609	    );
610	
611	    // ACK immediately so Synology Chat won't remain in "Processing..."
612	    respondNoContent(res);
613	    await processAuthorizedSynologyWebhook({
614	      account,
615	      deliver,
616	      log,
617	      message: authorized.message,
618	    });
619	  };
620	}
