166	    }
167	    const transport = parsedUrl.protocol === "https:" ? https : http;
168	
169	    transport
170	      .get(listUrl, { rejectUnauthorized: !allowInsecureSsl } as any, (res) => {
171	        let data = "";
172	        res.on("data", (c: Buffer) => {
173	          data += c.toString();
174	        });
