/**
 * Type definitions for the PulseBoard channel plugin.
 *
 * PulseBoard is a real-time bulletin board messaging platform where users
 * post messages to named "boards" (group chat) and can also send direct
 * messages (DMs).
 */

type PulseBoardConfigFields = {
  enabled?: boolean;
  apiKey?: string;
  apiUrl?: string;
  webhookPath?: string;
  webhookSecret?: string;
  dmPolicy?: "open" | "allowlist" | "disabled";
  allowedUserIds?: string | string[];
  rateLimitPerMinute?: number;
  botName?: string;
  defaultBoard?: string;
};

export type PulseBoardWebhookPathSource = "default" | "inherited-base" | "explicit";

/** Raw channel config from openclaw.json channels.pulseboard */
export interface PulseBoardChannelConfig extends PulseBoardConfigFields {
  accounts?: Record<string, PulseBoardAccountRaw>;
}

/** Raw per-account config (overrides base config) */
export interface PulseBoardAccountRaw extends PulseBoardConfigFields {}

/** Fully resolved account config with defaults applied */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  enabled: boolean;
  apiKey: string;
  apiUrl: string;
  webhookPath: string;
  webhookPathSource: PulseBoardWebhookPathSource;
  webhookSecret: string;
  dmPolicy: "open" | "allowlist" | "disabled";
  allowedUserIds: string[];
  rateLimitPerMinute: number;
  botName: string;
  defaultBoard: string;
}

/** Payload received from PulseBoard outgoing webhook */
export interface PulseBoardWebhookPayload {
  token: string;
  board_id?: string;
  board_name?: string;
  user_id: string;
  username: string;
  message_id?: string;
  timestamp?: string;
  text: string;
  chat_type: "direct" | "group";
}

