/**
 * Account resolution: reads config from channels.pulseboard,
 * merges per-account overrides, falls back to environment variables.
 */

import {
  DEFAULT_ACCOUNT_ID,
  listCombinedAccountIds,
  resolveMergedAccountConfig,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/account-resolution";
import type {
  PulseBoardChannelConfig,
  ResolvedPulseBoardAccount,
  PulseBoardWebhookPathSource,
} from "./types.js";

/** Extract the channel config from the full OpenClaw config object. */
function getChannelConfig(cfg: OpenClawConfig): PulseBoardChannelConfig | undefined {
  return cfg?.channels?.["pulseboard"];
}

function resolveImplicitAccountId(channelCfg: PulseBoardChannelConfig): string | undefined {
  return channelCfg.apiKey || process.env.PULSEBOARD_API_KEY ? DEFAULT_ACCOUNT_ID : undefined;
}

function getRawAccountConfig(
  channelCfg: PulseBoardChannelConfig,
  accountId: string,
): PulseBoardChannelConfig {
  if (accountId === DEFAULT_ACCOUNT_ID) {
    return channelCfg;
  }
  return channelCfg.accounts?.[accountId] ?? {};
}

function hasExplicitWebhookPath(rawAccount: PulseBoardChannelConfig | undefined): boolean {
  return typeof rawAccount?.webhookPath === "string" && rawAccount.webhookPath.trim().length > 0;
}

function resolveWebhookPathSource(params: {
  accountId: string;
  channelCfg: PulseBoardChannelConfig;
  rawAccount: PulseBoardChannelConfig;
}): PulseBoardWebhookPathSource {
  if (hasExplicitWebhookPath(params.rawAccount)) {
    return "explicit";
  }
  if (params.accountId !== DEFAULT_ACCOUNT_ID && hasExplicitWebhookPath(params.channelCfg)) {
    return "inherited-base";
  }
  return "default";
}

/** Parse allowedUserIds from string or array to string[]. */
function parseAllowedUserIds(raw: string | string[] | undefined): string[] {
  if (!raw) return [];
  if (Array.isArray(raw)) return raw.filter(Boolean);
  return raw
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);
}

function parseRateLimitPerMinute(raw: string | undefined): number {
  if (raw == null) {
    return 30;
  }
  const trimmed = raw.trim();
  if (!/^-?\d+$/.test(trimmed)) {
    return 30;
  }
  return Number.parseInt(trimmed, 10);
}

/**
 * List all configured account IDs for this channel.
 * Returns ["default"] if there's a base config, plus any named accounts.
 */
export function listAccountIds(cfg: OpenClawConfig): string[] {
  const channelCfg = getChannelConfig(cfg);
  if (!channelCfg) {
    return [];
  }

  return listCombinedAccountIds({
    configuredAccountIds: Object.keys(channelCfg.accounts ?? {}),
    implicitAccountId: resolveImplicitAccountId(channelCfg),
  });
}

/**
 * Resolve a specific account by ID with full defaults applied.
 * Falls back to env vars for the "default" account.
 */
export function resolveAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const channelCfg = getChannelConfig(cfg) ?? {};
  const id = accountId || DEFAULT_ACCOUNT_ID;
  const rawAccount = getRawAccountConfig(channelCfg, id);
  const merged = resolveMergedAccountConfig<Record<string, unknown> & PulseBoardChannelConfig>({
    channelConfig: channelCfg as Record<string, unknown> & PulseBoardChannelConfig,
    accounts: channelCfg.accounts as
      | Record<string, Partial<Record<string, unknown> & PulseBoardChannelConfig>>
      | undefined,
    accountId: id,
  });

  // Env var fallbacks (primarily for the "default" account)
  const envApiKey = process.env.PULSEBOARD_API_KEY ?? "";
  const envApiUrl = process.env.PULSEBOARD_API_URL ?? "https://api.pulseboard.example/v1";
  const envWebhookSecret = process.env.PULSEBOARD_WEBHOOK_SECRET ?? "";
  const envAllowedUserIds = process.env.PULSEBOARD_ALLOWED_USER_IDS ?? "";
  const envRateLimitValue = parseRateLimitPerMinute(process.env.PULSEBOARD_RATE_LIMIT);
  const envBotName = process.env.OPENCLAW_BOT_NAME ?? "OpenClaw";
  const webhookPathSource = resolveWebhookPathSource({ accountId: id, channelCfg, rawAccount });

  // Merge: account override > base channel config > env var
  return {
    accountId: id,
    enabled: merged.enabled ?? true,
    apiKey: merged.apiKey ?? envApiKey,
    apiUrl: merged.apiUrl ?? envApiUrl,
    webhookPath: merged.webhookPath ?? "/webhook/pulseboard",
    webhookPathSource,
    webhookSecret: merged.webhookSecret ?? envWebhookSecret,
    dmPolicy: merged.dmPolicy ?? "allowlist",
    allowedUserIds: parseAllowedUserIds(merged.allowedUserIds ?? envAllowedUserIds),
    rateLimitPerMinute: merged.rateLimitPerMinute ?? envRateLimitValue,
    botName: merged.botName ?? envBotName,
    defaultBoard: merged.defaultBoard ?? "general",
  };
}

