import type { ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard";

export type PulseBoardInboundMessage = {
  body: string;
  from: string;
  senderName: string;
  provider: string;
  chatType: "direct" | "group";
  accountId: string;
  commandAuthorized: boolean;
  boardId?: string;
  boardName?: string;
};

export function buildPulseBoardInboundContext<TContext>(params: {
  finalizeInboundContext: (ctx: Record<string, unknown>) => TContext;
  account: ResolvedPulseBoardAccount;
  msg: PulseBoardInboundMessage;
  sessionKey: string;
}): TContext {
  const { account, msg, sessionKey } = params;

  // For group messages, the "To" is the board; for DMs, it's the sender
  const to =
    msg.chatType === "group" && msg.boardId
      ? `pulseboard:board:${msg.boardId}`
      : `pulseboard:${msg.from}`;

  return params.finalizeInboundContext({
    Body: msg.body,
    RawBody: msg.body,
    CommandBody: msg.body,
    From: `pulseboard:${msg.from}`,
    To: to,
    SessionKey: sessionKey,
    AccountId: account.accountId,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: to,
    ChatType: msg.chatType,
    SenderName: msg.senderName,
    SenderId: msg.from,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    ConversationLabel:
      msg.chatType === "group" ? msg.boardName || msg.boardId || "board" : msg.senderName || msg.from,
    Timestamp: Date.now(),
    CommandAuthorized: msg.commandAuthorized,
  });
}

