import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
import { sendMessage } from "./client.js";
import { buildPulseBoardInboundContext, type PulseBoardInboundMessage } from "./inbound-context.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { buildPulseBoardInboundSessionKey } from "./session-key.js";
import type { ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard";

type PulseBoardChannelLog = {
  info?: (...args: unknown[]) => void;
};

function resolvePulseBoardInboundRoute(params: {
  cfg: OpenClawConfig;
  account: ResolvedPulseBoardAccount;
  peerId: string;
  chatType: "direct" | "group";
}) {
  const rt = getPulseBoardRuntime();
  const route = rt.channel.routing.resolveAgentRoute({
    cfg: params.cfg,
    channel: CHANNEL_ID,
    accountId: params.account.accountId,
    peer:
      params.chatType === "group"
        ? { kind: "group", id: params.peerId }
        : { kind: "direct", id: params.peerId },
  });
  return {
    rt,
    route,
    sessionKey: buildPulseBoardInboundSessionKey({
      agentId: route.agentId,
      accountId: params.account.accountId,
      peerId: params.peerId,
      chatType: params.chatType,
      identityLinks: params.cfg.session?.identityLinks,
    }),
  };
}

async function deliverPulseBoardReply(params: {
  account: ResolvedPulseBoardAccount;
  target: string;
  chatType: "direct" | "group";
  payload: { text?: string; body?: string };
}): Promise<void> {
  const text = params.payload.text ?? params.payload.body;
  if (!text) {
    return;
  }
  await sendMessage(
    params.account.apiUrl,
    params.account.apiKey,
    text,
    params.target,
    params.chatType,
  );
}

export async function dispatchPulseBoardInboundTurn(params: {
  account: ResolvedPulseBoardAccount;
  msg: PulseBoardInboundMessage;
  log?: PulseBoardChannelLog;
}): Promise<null> {
  const rt = getPulseBoardRuntime();
  const currentCfg = await rt.config.loadConfig();

  // For group messages, session is per-board; for DMs, per-user
  const peerId =
    params.msg.chatType === "group" && params.msg.boardId
      ? params.msg.boardId
      : params.msg.from;

  const resolved = resolvePulseBoardInboundRoute({
    cfg: currentCfg,
    account: params.account,
    peerId,
    chatType: params.msg.chatType,
  });
  const msgCtx = buildPulseBoardInboundContext({
    finalizeInboundContext: resolved.rt.channel.reply.finalizeInboundContext,
    account: params.account,
    msg: params.msg,
    sessionKey: resolved.sessionKey,
  });

  // Reply target: for group messages, reply to the board; for DMs, reply to the sender
  const replyTarget = peerId;

  await resolved.rt.channel.reply.dispatchReplyWithBufferedBlockDispatcher({
    ctx: msgCtx,
    cfg: currentCfg,
    dispatcherOptions: {
      deliver: async (payload: { text?: string; body?: string }) => {
        await deliverPulseBoardReply({
          account: params.account,
          target: replyTarget,
          chatType: params.msg.chatType,
          payload,
        });
      },
      onReplyStart: () => {
        params.log?.info?.(`Agent reply started for ${params.msg.from}`);
      },
    },
  });

  return null;
}

