function extractSecretFromHeaders(req: IncomingMessage): string | undefined {
  const explicit =
    headerValue(req.headers["x-pulseboard-secret"]) ??
    headerValue(req.headers["x-webhook-secret"]) ??
    headerValue(req.headers["x-openclaw-token"]);
  if (explicit) return explicit;

  const auth = headerValue(req.headers.authorization);
