    for (const item of header) {
      const trimmed = item?.trim();
      if (trimmed) return trimmed;
    }
    return undefined;
  }
  if (header === null || header === undefined) return undefined;
  const str = String(header).trim();
  return str.length > 0 ? str : undefined;
