type PulseBoardWebhookAuthorization =
  | { ok: false; statusCode: number; error: string }
  | { ok: true; commandAuthorized: boolean };

type AuthorizedPulseBoardWebhook = {
  payload: PulseBoardWebhookPayload;
  body: string;
  commandAuthorized: boolean;
  preview: string;
};

async function parseWebhookPayloadRequest(params: {
  req: IncomingMessage;
  res: ServerResponse;
  log?: WebhookHandlerDeps["log"];
}): Promise<{ ok: false } | { ok: true; payload: PulseBoardWebhookPayload }> {
  const bodyResult = await readBody(params.req);
  if (!bodyResult.ok) {
    params.log?.error("Failed to read request body", bodyResult.error);
