  req: IncomingMessage;
  account: ResolvedPulseBoardAccount;
  payload: PulseBoardWebhookPayload;
  invalidSecretRateLimiter: InvalidSecretRateLimiter;
  rateLimiter: RateLimiter;
  log?: WebhookHandlerDeps["log"];
}): PulseBoardWebhookAuthorization {
  const invalidSecretRateLimitKey = getPulseBoardWebhookInvalidSecretRateLimitKey(params.req);
  if (params.invalidSecretRateLimiter.isLocked(invalidSecretRateLimitKey)) {
    params.log?.warn(`Rate limit exceeded for remote IP: ${invalidSecretRateLimitKey}`);
    return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
  }

  if (!validateWebhookSecret(params.payload.token, params.account.webhookSecret)) {
    if (params.invalidSecretRateLimiter.recordFailure(invalidSecretRateLimitKey)) {
      params.log?.warn(`Rate limit exceeded for remote IP: ${invalidSecretRateLimitKey}`);
      return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
    }
    params.log?.warn(`Invalid webhook secret from ${params.req.socket?.remoteAddress}`);
    return { ok: false, statusCode: 401, error: "Invalid webhook secret" };
  }

  // For DMs, check DM policy; group messages are always allowed if secret is valid
  if (params.payload.chat_type === "direct") {
    const auth = authorizeUserForDm(
      params.payload.user_id,
      params.account.dmPolicy,
      params.account.allowedUserIds,
    );
    if (!auth.allowed) {
      if (auth.reason === "disabled") {
        return { ok: false, statusCode: 403, error: "DMs are disabled" };
      }
      if (auth.reason === "allowlist-empty") {
        params.log?.warn(
          "PulseBoard allowlist is empty while dmPolicy=allowlist; rejecting message",
        );
        return {
          ok: false,
          statusCode: 403,
          error: "Allowlist is empty. Configure allowedUserIds or use dmPolicy=open.",
        };
      }
      params.log?.warn(`Unauthorized user: ${params.payload.user_id}`);
      return { ok: false, statusCode: 403, error: "User not authorized" };
    }
  }

  if (!params.rateLimiter.check(params.payload.user_id)) {
    params.log?.warn(`Rate limit exceeded for user: ${params.payload.user_id}`);
    return { ok: false, statusCode: 429, error: "Rate limit exceeded" };
  }

  return { ok: true, commandAuthorized: true };
}

async function parseAndAuthorizePulseBoardWebhook(params: {
  req: IncomingMessage;
  res: ServerResponse;
  account: ResolvedPulseBoardAccount;
  invalidSecretRateLimiter: InvalidSecretRateLimiter;
  rateLimiter: RateLimiter;
  log?: WebhookHandlerDeps["log"];
}): Promise<{ ok: false } | { ok: true; message: AuthorizedPulseBoardWebhook }> {
  const parsed = await parseWebhookPayloadRequest(params);
  if (!parsed.ok) {
    return { ok: false };
  }

  const authorized = authorizePulseBoardWebhook({
    req: params.req,
    account: params.account,
    payload: parsed.payload,
    invalidSecretRateLimiter: params.invalidSecretRateLimiter,
    rateLimiter: params.rateLimiter,
    log: params.log,
  });
  if (!authorized.ok) {
    respondJson(params.res, authorized.statusCode, { error: authorized.error });
    return { ok: false };
  }

  const cleanText = sanitizeInput(parsed.payload.text);
  if (!cleanText) {
    respondNoContent(params.res);
    return { ok: false };
  }
  const preview = cleanText.length > 100 ? `${cleanText.slice(0, 100)}...` : cleanText;
  return {
    ok: true,
    message: {
      payload: parsed.payload,
      body: cleanText,
      commandAuthorized: authorized.commandAuthorized,
      preview,
    },
  };
}

async function processAuthorizedPulseBoardWebhook(params: {
  account: ResolvedPulseBoardAccount;
  deliver: WebhookHandlerDeps["deliver"];
  log?: WebhookHandlerDeps["log"];
  message: AuthorizedPulseBoardWebhook;
}): Promise<void> {
  try {
    const deliverPromise = params.deliver({
      body: params.message.body,
      from: params.message.payload.user_id,
      senderName: params.message.payload.username,
      provider: "pulseboard",
      chatType: params.message.payload.chat_type,
      accountId: params.account.accountId,
      commandAuthorized: params.message.commandAuthorized,
      boardId: params.message.payload.board_id,
      boardName: params.message.payload.board_name,
    });
    const timeoutPromise = new Promise<null>((_, reject) =>
      setTimeout(() => reject(new Error("Agent response timeout (120s)")), 120_000),
    );
    const reply = await Promise.race([deliverPromise, timeoutPromise]);
    if (!reply) {
      return;
    }

    const target =
      params.message.payload.chat_type === "group" && params.message.payload.board_id
        ? params.message.payload.board_id
        : params.message.payload.user_id;

    await sendMessage(
      params.account.apiUrl,
      params.account.apiKey,
      reply,
      target,
      params.message.payload.chat_type,
    );
    const replyPreview = reply.length > 100 ? `${reply.slice(0, 100)}...` : reply;
    params.log?.info?.(
      `Reply sent to ${params.message.payload.username} (${params.message.payload.user_id}): ${replyPreview}`,
    );
  } catch (err) {
    const errMsg = err instanceof Error ? `${err.message}\n${err.stack}` : String(err);
    params.log?.error?.(
      `Failed to process message from ${params.message.payload.username}: ${errMsg}`,
    );
    // Attempt to send error notification to the user
    const errorTarget =
      params.message.payload.chat_type === "group" && params.message.payload.board_id
        ? params.message.payload.board_id
        : params.message.payload.user_id;

    await sendMessage(
      params.account.apiUrl,
      params.account.apiKey,
      "Sorry, an error occurred while processing your message.",
      errorTarget,
      params.message.payload.chat_type,
    );
  }
}

// Import sendMessage for use in processAuthorizedPulseBoardWebhook
import { sendMessage } from "./client.js";

/**
 * Create an HTTP request handler for PulseBoard outgoing webhooks.
 *
 * This handler:
 * 1. Parses JSON payload
 * 2. Validates webhook secret (constant-time)
 * 3. Checks user allowlist (for DMs)
 * 4. Checks rate limit
 * 5. Sanitizes input
 * 6. Immediately ACKs request (204)
 * 7. Delivers to the agent asynchronously and sends reply via PulseBoard API
 */
export function createWebhookHandler(deps: WebhookHandlerDeps) {
  const { account, deliver, log } = deps;
  const rateLimiter = getRateLimiter(account);
  const invalidSecretRateLimiter = getInvalidSecretRateLimiter(account);

  return async (req: IncomingMessage, res: ServerResponse) => {
    // Only accept POST
    if (req.method !== "POST") {
      respondJson(res, 405, { error: "Method not allowed" });
      return;
    }
    const requestLifecycle = beginWebhookRequestPipelineOrReject({
      req,
      res,
      inFlightLimiter: webhookInFlightLimiter,
      inFlightKey: getPulseBoardWebhookInFlightKey(account),
    });
    if (!requestLifecycle.ok) {
      return;
    }

    let authorized: Awaited<ReturnType<typeof parseAndAuthorizePulseBoardWebhook>>;
    try {
      authorized = await parseAndAuthorizePulseBoardWebhook({
        req,
        res,
        account,
        invalidSecretRateLimiter,
        rateLimiter,
        log,
      });
    } finally {
      requestLifecycle.release();
    }
    if (!authorized.ok) {
      return;
    }

    log?.info(
      `Message from ${authorized.message.payload.username} (${authorized.message.payload.user_id}) [${authorized.message.payload.chat_type}]: ${authorized.message.preview}`,
    );

    // ACK immediately so PulseBoard does not timeout
    respondNoContent(res);
    await processAuthorizedPulseBoardWebhook({
      account,
      deliver,
      log,
      message: authorized.message,
    });
  };
}

