  for (const limiter of rateLimiters.values()) {
    limiter.clear();
  }
  rateLimiters.clear();
  for (const limiter of invalidSecretRateLimiters.values()) {
    limiter.clear();
  }
  invalidSecretRateLimiters.clear();
  webhookInFlightLimiter.clear();
}

