/**
 * PulseBoard Channel Plugin for OpenClaw.
 *
 * Implements the ChannelPlugin interface for PulseBoard, a fictional
 * real-time bulletin board messaging platform supporting both board
 * posts (group) and direct messages.
 */

import type { OpenClawConfig } from "openclaw/plugin-sdk/account-resolution";
import {
  createHybridChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { waitUntilAbort } from "openclaw/plugin-sdk/channel-lifecycle";
import {
  composeWarningCollectors,
  createConditionalWarningCollector,
  projectAccountConfigWarningCollector,
  projectAccountWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";
import { createEmptyChannelDirectoryAdapter } from "openclaw/plugin-sdk/directory-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/setup";
import { listAccountIds, resolveAccount } from "./accounts.js";
import { pulseBoardApprovalAuth } from "./approval-auth.js";
import { sendMessage } from "./client.js";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";
import {
  collectPulseBoardGatewayRoutingWarnings,
  registerPulseBoardWebhookRoute,
  validatePulseBoardGatewayAccountStartup,
} from "./gateway-runtime.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import type { ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard";

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: CHANNEL_ID,
  resolvePolicy: (account) => account.dmPolicy,
  resolveAllowFrom: (account) => account.allowedUserIds,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "allowlist",
  approveHint: "openclaw pairing approve pulseboard <code>",
  normalizeEntry: (raw) => raw.toLowerCase().trim(),
});

type PulseBoardChannelGatewayContext = {
  cfg: OpenClawConfig;
  accountId: string;
  abortSignal: AbortSignal;
  log?: {
    info: (message: string) => void;
    warn: (message: string) => void;
    error: (message: string) => void;
  };
};
type PulseBoardChannelOutboundContext = {
  cfg: OpenClawConfig;
  to: string;
  text?: string;
  accountId?: string | null;
};
type PulseBoardChannelSendTextContext = PulseBoardChannelOutboundContext & { text: string };
type PulseBoardSecurityWarningContext = {
  cfg: OpenClawConfig;
  account: ResolvedPulseBoardAccount;
};

const pulseBoardConfigAdapter = createHybridChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: CHANNEL_ID,
  listAccountIds,
  resolveAccount,
  defaultAccountId: () => DEFAULT_ACCOUNT_ID,
  clearBaseFields: [
    "apiKey",
    "apiUrl",
    "webhookPath",
    "webhookSecret",
    "dmPolicy",
    "allowedUserIds",
    "rateLimitPerMinute",
    "botName",
    "defaultBoard",
  ],
  resolveAllowFrom: (account) => account.allowedUserIds,
  formatAllowFrom: (allowFrom) =>
    allowFrom.map((entry) => String(entry).trim().toLowerCase()).filter(Boolean),
});

const collectPulseBoardSecurityWarnings =
  createConditionalWarningCollector<ResolvedPulseBoardAccount>(
    (account) =>
      !account.webhookSecret &&
      "- PulseBoard: webhookSecret is not configured. The webhook will reject all requests.",
    (account) =>
      !account.apiKey &&
      "- PulseBoard: apiKey is not configured. The bot cannot send replies.",
    (account) =>
      account.dmPolicy === "open" &&
      '- PulseBoard: dmPolicy="open" allows any user to DM the bot. Consider "allowlist" for production use.',
    (account) =>
      account.dmPolicy === "allowlist" &&
      account.allowedUserIds.length === 0 &&
      '- PulseBoard: dmPolicy="allowlist" with empty allowedUserIds blocks all DM senders. Add users or set dmPolicy="open".',
  );

type PulseBoardOutboundResult = {
  channel: typeof CHANNEL_ID;
  messageId: string;
  chatId: string;
};

type PulseBoardPlugin = Omit<
  ChannelPlugin<ResolvedPulseBoardAccount>,
  "pairing" | "security" | "messaging" | "directory" | "outbound" | "gateway" | "agentPrompt"
> & {
  pairing: {
    idLabel: string;
    normalizeAllowEntry?: (entry: string) => string;
    notifyApproval: (params: { cfg: OpenClawConfig; id: string }) => Promise<void>;
  };
  security: {
    resolveDmPolicy: (params: {
      cfg: OpenClawConfig;
      account: ResolvedPulseBoardAccount;
    }) => {
      policy: string | null | undefined;
      allowFrom?: Array<string | number>;
      normalizeEntry?: (raw: string) => string;
    } | null;
    collectWarnings: (params: {
      cfg: OpenClawConfig;
      account: ResolvedPulseBoardAccount;
    }) => string[];
  };
  messaging: {
    normalizeTarget: (target: string) => string | undefined;
    targetResolver: {
      looksLikeId: (id: string) => boolean;
      hint: string;
    };
  };
  directory: {
    self?: NonNullable<ChannelPlugin<ResolvedPulseBoardAccount>["directory"]>["self"];
    listPeers?: NonNullable<ChannelPlugin<ResolvedPulseBoardAccount>["directory"]>["listPeers"];
    listGroups?: NonNullable<ChannelPlugin<ResolvedPulseBoardAccount>["directory"]>["listGroups"];
  };
  outbound: {
    deliveryMode: "gateway";
    textChunkLimit: number;
    sendText: (ctx: PulseBoardChannelSendTextContext) => Promise<PulseBoardOutboundResult>;
  };
  gateway: {
    startAccount: (ctx: PulseBoardChannelGatewayContext) => Promise<unknown>;
    stopAccount: (ctx: PulseBoardChannelGatewayContext) => Promise<void>;
  };
  agentPrompt: {
    messageToolHints: () => string[];
  };
};

const collectPulseBoardRoutingWarnings = projectAccountConfigWarningCollector<
  ResolvedPulseBoardAccount,
  OpenClawConfig,
  PulseBoardSecurityWarningContext
>(
  (cfg) => cfg,
  ({ account, cfg }) => collectPulseBoardGatewayRoutingWarnings({ account, cfg }),
);

function resolveOutboundAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  return resolveAccount(cfg ?? {}, accountId);
}

/**
 * Determine chat type from a target string.
 * Board targets use the prefix "board:" while DM targets are plain user IDs.
 */
function resolveChatTypeFromTarget(target: string): "direct" | "group" {
  return target.startsWith("board:") ? "group" : "direct";
}

/** Strip the "board:" prefix from a board target. */
function stripBoardPrefix(target: string): string {
  return target.startsWith("board:") ? target.slice(6) : target;
}

export function createPulseBoardPlugin(): PulseBoardPlugin {
  return createChatChannelPlugin({
    base: {
      id: CHANNEL_ID,
      meta: {
