import {
  createAllowFromSection,
  createStandardChannelSetupStatus,
  DEFAULT_ACCOUNT_ID,
  formatDocsLink,
  mergeAllowFromEntries,
  normalizeAccountId,
  setSetupChannelEnabled,
  splitSetupEntries,
  type ChannelSetupAdapter,
  type ChannelSetupWizard,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/setup";
import { listAccountIds, resolveAccount } from "./accounts.js";
import type { PulseBoardAccountRaw, PulseBoardChannelConfig } from "./types.js";

const channel = "pulseboard" as const;
const DEFAULT_WEBHOOK_PATH = "/webhook/pulseboard";

const PULSEBOARD_SETUP_HELP_LINES = [
  "1) Create a PulseBoard bot in your workspace settings and copy its API key",
  "2) Copy the webhook secret from your bot configuration",
  `3) Point the outgoing webhook to https://<gateway-host>${DEFAULT_WEBHOOK_PATH}`,
  "4) Keep allowed user IDs handy for DM allowlisting",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by user id.",
  "Examples:",
  "- pb_user_abc123",
  "- pulseboard:pb_user_abc123",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function getChannelConfig(cfg: OpenClawConfig): PulseBoardChannelConfig {
  return (cfg.channels?.[channel] as PulseBoardChannelConfig | undefined) ?? {};
}

function getRawAccountConfig(cfg: OpenClawConfig, accountId: string): PulseBoardAccountRaw {
  const channelConfig = getChannelConfig(cfg);
  if (accountId === DEFAULT_ACCOUNT_ID) {
    return channelConfig;
  }
  return channelConfig.accounts?.[accountId] ?? {};
}

function patchPulseBoardAccountConfig(params: {
  cfg: OpenClawConfig;
  accountId: string;
  patch: Record<string, unknown>;
  clearFields?: string[];
  enabled?: boolean;
}): OpenClawConfig {
  const channelConfig = getChannelConfig(params.cfg);
  if (params.accountId === DEFAULT_ACCOUNT_ID) {
    const nextChannelConfig = { ...channelConfig } as Record<string, unknown>;
    for (const field of params.clearFields ?? []) {
      delete nextChannelConfig[field];
    }
    return {
      ...params.cfg,
      channels: {
        ...params.cfg.channels,
        [channel]: {
          ...nextChannelConfig,
          ...(params.enabled ? { enabled: true } : {}),
          ...params.patch,
        },
      },
    };
  }

  const nextAccounts = { ...(channelConfig.accounts ?? {}) } as Record<
    string,
    Record<string, unknown>
  >;
  const nextAccountConfig = { ...(nextAccounts[params.accountId] ?? {}) };
  for (const field of params.clearFields ?? []) {
    delete nextAccountConfig[field];
  }
  nextAccounts[params.accountId] = {
    ...nextAccountConfig,
    ...(params.enabled ? { enabled: true } : {}),
    ...params.patch,
  };

  return {
    ...params.cfg,
    channels: {
      ...params.cfg.channels,
      [channel]: {
        ...channelConfig,
        ...(params.enabled ? { enabled: true } : {}),
        accounts: nextAccounts,
      },
    },
  };
}

function isPulseBoardConfigured(cfg: OpenClawConfig, accountId: string): boolean {
  const account = resolveAccount(cfg, accountId);
  return Boolean(account.apiKey.trim() && account.webhookSecret.trim());
}

function validateApiUrl(value: string): string | undefined {
  try {
    const parsed = new URL(value);
    if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
      return "API URL must use http:// or https://.";
    }
  } catch {
    return "API URL must be a valid URL.";
  }
  return undefined;
}

function validateWebhookPath(value: string): string | undefined {
  const trimmed = value.trim();
  if (!trimmed) {
    return undefined;
  }
  return trimmed.startsWith("/") ? undefined : "Webhook path must start with /.";
}

function parsePulseBoardUserId(value: string): string | null {
  const cleaned = value.replace(/^pulseboard:/i, "").trim();
  return /^[\w-]+$/.test(cleaned) ? cleaned : null;
}

function resolveExistingAllowedUserIds(cfg: OpenClawConfig, accountId: string): string[] {
  const raw = getRawAccountConfig(cfg, accountId).allowedUserIds;
  if (Array.isArray(raw)) {
    return raw.map((value) => String(value).trim()).filter(Boolean);
  }
  return String(raw ?? "")
    .split(",")
    .map((value) => value.trim())
    .filter(Boolean);
}

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId) ?? DEFAULT_ACCOUNT_ID,
  validateInput: ({ accountId, input }) => {
    if (input.useEnv && accountId !== DEFAULT_ACCOUNT_ID) {
      return "PulseBoard env credentials only support the default account.";
    }
    if (!input.useEnv && !input.token?.trim()) {
      return "PulseBoard requires --token (API key) or --use-env.";
    }
    if (!input.url?.trim()) {
      return "PulseBoard requires --url for the API endpoint.";
    }
    const urlError = validateApiUrl(input.url.trim());
    if (urlError) {
      return urlError;
    }
    if (input.webhookPath?.trim()) {
      return validateWebhookPath(input.webhookPath.trim()) ?? null;
    }
    return null;
  },
  applyAccountConfig: ({ cfg, accountId, input }) =>
    patchPulseBoardAccountConfig({
      cfg,
      accountId,
      enabled: true,
      clearFields: input.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(input.useEnv ? {} : { apiKey: input.token?.trim() }),
        apiUrl: input.url?.trim(),
        ...(input.webhookPath?.trim() ? { webhookPath: input.webhookPath.trim() } : {}),
      },
    }),
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key + webhook secret",
    configuredHint: "configured",
    unconfiguredHint: "needs API key + webhook secret",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listAccountIds(cfg).some((accountId) => isPulseBoardConfigured(cfg, accountId)),
    resolveExtraStatusLines: ({ cfg }) => [`Accounts: ${listAccountIds(cfg).length || 0}`],
  }),
  introNote: {
    title: "PulseBoard webhook setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  credentials: [
    {
      inputKey: "token",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "Enter PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolveAccount(cfg, accountId);
        const raw = getRawAccountConfig(cfg, accountId);
        return {
          accountConfigured: isPulseBoardConfigured(cfg, accountId),
          hasConfiguredValue: Boolean(raw.apiKey?.trim()),
          resolvedValue: account.apiKey.trim() || undefined,
          envValue:
            accountId === DEFAULT_ACCOUNT_ID
              ? process.env.PULSEBOARD_API_KEY?.trim() || undefined
              : undefined,
        };
      },
      applyUseEnv: async ({ cfg, accountId }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, accountId, resolvedValue }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "url",
      message: "PulseBoard API URL",
      placeholder: "https://api.pulseboard.example/v1",
      helpTitle: "PulseBoard API endpoint",
      helpLines: [
        "Use the API URL from your PulseBoard workspace settings.",
        "This is the URL OpenClaw uses to send replies back to PulseBoard.",
      ],
      currentValue: ({ cfg, accountId }) => getRawAccountConfig(cfg, accountId).apiUrl?.trim(),
      keepPrompt: (value) => `API URL set (${value}). Keep it?`,
      validate: ({ value }) => validateApiUrl(value),
      applySet: async ({ cfg, accountId, value }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          patch: { apiUrl: value.trim() },
        }),
    },
    {
      inputKey: "webhookSecret",
      message: "Webhook secret",
      placeholder: "your-webhook-secret",
      helpTitle: "PulseBoard webhook secret",
      helpLines: [
        "This secret is used to validate incoming webhook requests from PulseBoard.",
        "Find it in your PulseBoard bot configuration.",
      ],
      currentValue: ({ cfg, accountId }) =>
        getRawAccountConfig(cfg, accountId).webhookSecret?.trim(),
      keepPrompt: (value) => `Webhook secret set (${value ? "***" : "empty"}). Keep it?`,
